import { autoUpdater } from 'electron-updater'
import { BrowserWindow, app } from 'electron'
import { join } from 'path'
import { readFileSync } from 'fs'
import {
  getActiveUpdateSource,
  type UpdateSource
} from '../services/store'

let mainWindow: BrowserWindow | null = null

/**
 * 自动更新模块
 * 提供应用自动检查、下载和安装更新的功能
 */
export function useAutoUpdater() {
  // 配置自动更新服务器地址
  autoUpdater.autoDownload = false // 不自动下载，由用户确认
  autoUpdater.autoInstallOnAppQuit = true // 退出时自动安装

  /**
   * 设置主窗口引用，用于发送更新事件到渲染进程
   */
  const setMainWindow = (win: BrowserWindow) => {
    mainWindow = win
  }

  /**
   * 发送更新事件到渲染进程
   */
  const sendToRenderer = (channel: string, data?: unknown) => {
    if (mainWindow && !mainWindow.isDestroyed()) {
      mainWindow.webContents.send(channel, data)
    }
  }

  /**
   * 根据更新源配置设置 autoUpdater 的 feed URL
   */
  const applyUpdateSource = (source: UpdateSource): void => {
    if (source.type === 'github' && source.owner && source.repo) {
      autoUpdater.setFeedURL({
        provider: 'github',
        owner: source.owner,
        repo: source.repo
      })
      console.log(`[AutoUpdater] 更新源设为 GitHub: ${source.owner}/${source.repo}`)
    } else if (source.type === 'generic' && source.url) {
      autoUpdater.setFeedURL({
        provider: 'generic',
        url: source.url
      })
      console.log(`[AutoUpdater] 更新源设为 Generic: ${source.url}`)
    } else {
      console.warn('[AutoUpdater] 无效的更新源配置:', source)
    }
  }

  /**
   * 初始化更新源（启动时调用）
   */
  const initUpdateSource = (): void => {
    const source = getActiveUpdateSource()
    if (source) {
      applyUpdateSource(source)
    }
  }

  // 检查更新失败
  autoUpdater.on('error', (error) => {
    console.error('[AutoUpdater] 更新错误:', error)
    sendToRenderer('update:error', {
      message: error.message || '检查更新失败'
    })
  })

  // 检查更新中
  autoUpdater.on('checking-for-update', () => {
    console.log('[AutoUpdater] 正在检查更新...')
    sendToRenderer('update:checking')
  })

  // 发现新版本
  autoUpdater.on('update-available', (info) => {
    console.log('[AutoUpdater] 发现新版本:', info.version)
    sendToRenderer('update:available', {
      version: info.version,
      releaseDate: info.releaseDate,
      releaseNotes: info.releaseNotes
    })
  })

  // 当前已是最新版本
  autoUpdater.on('update-not-available', (info) => {
    console.log('[AutoUpdater] 当前已是最新版本')
    sendToRenderer('update:not-available', {
      version: info.version
    })
  })

  // 下载进度
  autoUpdater.on('download-progress', (progressInfo) => {
    const progress = {
      percent: progressInfo.percent,
      transferred: progressInfo.transferred,
      total: progressInfo.total,
      bytesPerSecond: progressInfo.bytesPerSecond
    }
    console.log(`[AutoUpdater] 下载进度: ${progress.percent.toFixed(1)}%`)
    sendToRenderer('update:download-progress', progress)
  })

  // 下载完成
  autoUpdater.on('update-downloaded', (info) => {
    console.log('[AutoUpdater] 更新下载完成:', info.version)
    sendToRenderer('update:downloaded', {
      version: info.version,
      releaseDate: info.releaseDate,
      releaseNotes: info.releaseNotes
    })
  })

  /**
   * 检查更新（先应用当前激活的更新源）
   */
  const checkForUpdates = async () => {
    try {
      // 每次检查前刷新更新源配置
      const source = getActiveUpdateSource()
      if (source) {
        applyUpdateSource(source)
      }

      const result = await autoUpdater.checkForUpdates()
      return {
        success: true,
        updateInfo: result?.updateInfo ? {
          version: result.updateInfo.version,
          releaseDate: result.updateInfo.releaseDate,
          releaseNotes: result.updateInfo.releaseNotes
        } : null
      }
    } catch (error: unknown) {
      console.error('[AutoUpdater] 检查更新失败:', error)
      return {
        success: false,
        error: (error as Error).message || '检查更新失败'
      }
    }
  }

  /**
   * 下载更新
   */
  const downloadUpdate = async () => {
    try {
      await autoUpdater.downloadUpdate()
      return { success: true }
    } catch (error: unknown) {
      console.error('[AutoUpdater] 下载更新失败:', error)
      return {
        success: false,
        error: (error as Error).message || '下载更新失败'
      }
    }
  }

  /**
   * 安装更新并重启
   * @param isSilent 是否静默安装（不提示用户）
   */
  const quitAndInstall = (isSilent = false) => {
    autoUpdater.quitAndInstall(isSilent, true)
  }

  /**
   * 获取当前版本
   */
  const getCurrentVersion = () => {
    return app.getVersion()
  }

  /**
   * 获取更新信息（从本地 latest.yml 读取，如果存在）
   */
  const getUpdateInfo = () => {
    try {
      const latestYmlPath = join(app.getAppPath(), 'latest.yml')
      const content = readFileSync(latestYmlPath, 'utf-8')
      // 简单解析 YAML 获取版本
      const versionMatch = content.match(/version:\s*(.+)/)
      return {
        success: true,
        version: versionMatch ? versionMatch[1].trim() : null
      }
    } catch {
      return {
        success: false,
        version: null
      }
    }
  }

  return {
    setMainWindow,
    checkForUpdates,
    downloadUpdate,
    quitAndInstall,
    getCurrentVersion,
    getUpdateInfo,
    initUpdateSource,
    applyUpdateSource
  }
}

// 导出单例实例的函数
let autoUpdaterInstance: ReturnType<typeof useAutoUpdater> | null = null

export function getAutoUpdater() {
  if (!autoUpdaterInstance) {
    autoUpdaterInstance = useAutoUpdater()
  }
  return autoUpdaterInstance
}

import { ipcMain, BrowserWindow } from 'electron'
import { proxyChatCompletions, activeRequests, executeTool } from '../services/ai-proxy'
import { resolvePendingRendererTool } from '../services/workflow-tool-dispatcher'

export function registerChatIpcHandlers(): void {
  // Workflow engine 工具执行通道
  ipcMain.handle('agent:execTool', async (_event, toolType: string, params: Record<string, any>, targetTabId?: string) => {
    const result = await executeTool(toolType, params || {}, targetTabId)
    // electron-store 返回值可能包含不可序列化的内部属性（Proxy/getter），
    // IPC handle 使用结构化克隆传输，需先转为纯 JSON 兼容对象
    return typeof result === 'string' ? result : JSON.parse(JSON.stringify(result))
  })

  ipcMain.handle('chat:completions', async (event, params) => {
    const mainWindow = BrowserWindow.fromWebContents(event.sender)
    if (!mainWindow) {
      throw new Error('No main window found')
    }
    // 异步代理，不阻塞 IPC response
    proxyChatCompletions(mainWindow, params).catch((err) => {
      if (!mainWindow.isDestroyed()) {
        mainWindow.webContents.send('on:chat:error', {
          requestId: params._requestId,
          error: err instanceof Error ? err.message : String(err),
        })
      }
    })
    return { started: true }
  })

  // 中止正在进行的聊天请求
  ipcMain.handle('chat:abort', (_event, requestId: string) => {
    const controller = activeRequests.get(requestId)
    if (controller) {
      controller.abort()
      activeRequests.delete(requestId)
      return { aborted: true }
    }
    return { aborted: false, reason: 'not found' }
  })

  ipcMain.handle('workflow-tool:respond', (_event, requestId: string, result: unknown) => {
    return { resolved: resolvePendingRendererTool(requestId, result) }
  })

  // ===== 浏览器交互工具（CDP） =====
  ipcMain.handle('browser:click', async (_event, args: { selector?: string; x?: number; y?: number; tabId?: string }) => {
    const wc = getWebContents(args.tabId)
    if (!wc) return { error: 'Tab not found' }
    if (args.selector) {
      await wc.executeJavaScript(`document.querySelector('${cssEscape(args.selector)}')?.click()`)
    } else if (args.x !== undefined && args.y !== undefined) {
      await wc.executeJavaScript(`
        const el = document.elementFromPoint(${args.x}, ${args.y})
        if (el) el.click()
      `)
    }
    return { success: true }
  })

  ipcMain.handle('browser:type', async (_event, args: { text: string; selector?: string; tabId?: string }) => {
    const wc = getWebContents(args.tabId)
    if (!wc) return { error: 'Tab not found' }
    if (args.selector) {
      const escaped = args.text.replace(/'/g, "\\'")
      await wc.executeJavaScript(`
        const el = document.querySelector('${cssEscape(args.selector!)}')
        if (el) { el.focus(); el.value = '${escaped}'; el.dispatchEvent(new Event('input', { bubbles: true })) }
      `)
    } else {
      const escaped = args.text.replace(/'/g, "\\'")
      await wc.executeJavaScript(`
        const el = document.activeElement
        if (el && (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA' || el.isContentEditable)) {
          if (el.isContentEditable) { el.textContent += '${escaped}' }
          else { el.value += '${escaped}'; el.dispatchEvent(new Event('input', { bubbles: true })) }
        }
      `)
    }
    return { success: true }
  })

  ipcMain.handle('browser:scroll', async (_event, args: { direction: 'up' | 'down' | 'left' | 'right'; amount: number; tabId?: string }) => {
    const wc = getWebContents(args.tabId)
    if (!wc) return { error: 'Tab not found' }
    const scrollMap: Record<string, string> = {
      up: `window.scrollBy(0, -${args.amount})`,
      down: `window.scrollBy(0, ${args.amount})`,
      left: `window.scrollBy(-${args.amount}, 0)`,
      right: `window.scrollBy(${args.amount}, 0)`,
    }
    await wc.executeJavaScript(scrollMap[args.direction] ?? '')
    return { success: true }
  })

  ipcMain.handle('browser:select', async (_event, args: { selector: string; value: string; tabId?: string }) => {
    const wc = getWebContents(args.tabId)
    if (!wc) return { error: 'Tab not found' }
    const escapedValue = args.value.replace(/'/g, "\\'")
    await wc.executeJavaScript(`
      const el = document.querySelector('${cssEscape(args.selector)}')
      if (el) { el.value = '${escapedValue}'; el.dispatchEvent(new Event('change', { bubbles: true })) }
    `)
    return { success: true }
  })

  ipcMain.handle('browser:hover', async (_event, args: { selector: string; tabId?: string }) => {
    const wc = getWebContents(args.tabId)
    if (!wc) return { error: 'Tab not found' }
    await wc.executeJavaScript(`
      const el = document.querySelector('${cssEscape(args.selector)}')
      if (el) { el.dispatchEvent(new MouseEvent('mouseenter', { bubbles: true })); el.dispatchEvent(new MouseEvent('mouseover', { bubbles: true })) }
    `)
    return { success: true }
  })

  ipcMain.handle('browser:get-content', async (_event, args: { tabId?: string }) => {
    const wc = getWebContents(args.tabId)
    if (!wc) return { error: 'Tab not found' }
    const content = await wc.executeJavaScript('document.body.innerText')
    return { content }
  })

  ipcMain.handle('browser:get-dom', async (_event, args: { selector: string; tabId?: string }) => {
    const wc = getWebContents(args.tabId)
    if (!wc) return { error: 'Tab not found' }
    const html = await wc.executeJavaScript(`
      const el = document.querySelector('${cssEscape(args.selector)}')
      el ? el.outerHTML : null
    `)
    return { html }
  })

  ipcMain.handle('browser:screenshot', async (_event, args: { tabId?: string; format?: string }) => {
    const wc = getWebContents(args.tabId)
    if (!wc) return { error: 'Tab not found' }
    const image = await wc.capturePage()
    const base64 = image.toPNG().toString('base64')
    return { data: base64, format: 'png' }
  })
}

/** CSS 选择器中的特殊字符转义 */
function cssEscape(selector: string): string {
  return selector.replace(/'/g, "\\'")
}

/** 获取指定 tabId 的 webContents */
function getWebContents(tabId?: string): Electron.WebContents | null {
  if (!tabId) return null
  const manager = (global as any).__webviewManager
  if (!manager) return null
  return manager.getWebContents?.(tabId) ?? null
}

import { ipcMain, shell, nativeImage, dialog, BrowserWindow } from 'electron'
import path from 'path'
import {
  checkConnection,
  getAria2Config,
  updateAria2Config,
  startAria2,
  stopAria2,
  addDownload,
  pauseDownload,
  resumeDownload,
  removeDownload,
  getActiveTasks,
  getWaitingTasks,
  getStoppedTasks,
  getGlobalStat,
  purgeDownloadResult,
  startNotificationMonitor,
  stopNotificationMonitor
} from '../services/aria2'
import { webviewManager } from '../services/webview-manager'

export function registerDownloadIpcHandlers(): void {
  ipcMain.handle('download:checkConnection', async () => {
    const connected = await checkConnection()
    webviewManager.setAria2Enabled(connected)
    if (connected) startNotificationMonitor()
    return connected
  })

  ipcMain.handle('download:getConfig', () => getAria2Config())

  ipcMain.handle('download:updateConfig', (_e, config) => updateAria2Config(config))

  ipcMain.handle('download:start', async () => {
    const ok = await startAria2()
    webviewManager.setAria2Enabled(ok)
    return ok
  })

  ipcMain.handle('download:stop', async () => {
    stopNotificationMonitor()
    await stopAria2()
    webviewManager.setAria2Enabled(false)
  })

  ipcMain.handle('download:add', (_e, url: string, options?: { filename?: string; dir?: string; headers?: string[]; cookies?: string; referer?: string }) =>
    addDownload(url, options)
  )

  ipcMain.handle('download:pause', (_e, gid: string) => pauseDownload(gid))

  ipcMain.handle('download:resume', (_e, gid: string) => resumeDownload(gid))

  ipcMain.handle('download:remove', (_e, gid: string) => removeDownload(gid))

  ipcMain.handle('download:listActive', () => getActiveTasks())

  ipcMain.handle('download:listWaiting', () => getWaitingTasks())

  ipcMain.handle('download:listStopped', () => getStoppedTasks())

  ipcMain.handle('download:globalStat', () => getGlobalStat())

  ipcMain.handle('download:purge', () => purgeDownloadResult())

  /** 在系统文件管理器中显示已下载的文件 */
  ipcMain.handle('download:showInFolder', async (_e, filePath: string) => {
    await shell.showItemInFolder(filePath)
  })

  /** 获取下载文件的完整路径（用于拖拽） */
  ipcMain.handle('download:getFilePath', (_e, dir: string, filename: string) => {
    return path.join(dir, filename)
  })

  /** 原生文件拖拽：通过主进程 startDrag 实现拖拽到外部应用 */
  ipcMain.on('download:startDrag', (event, filePath: string) => {
    // macOS 要求 icon 非空，使用 1x1 透明 PNG
    const icon = nativeImage.createFromBuffer(
      Buffer.from('iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==', 'base64')
    )
    event.sender.startDrag({ file: filePath, icon })
  })

  /** 双击打开已下载的文件 */
  ipcMain.handle('download:openFile', async (_e, filePath: string) => {
    await shell.openPath(filePath)
  })

  /** 选择下载目录 */
  ipcMain.handle('download:pickDirectory', async (_e, defaultPath?: string) => {
    const win = BrowserWindow.getFocusedWindow()
    const result = win
      ? await dialog.showOpenDialog(win, {
          title: '选择保存位置',
          defaultPath,
          properties: ['openDirectory', 'createDirectory']
        })
      : await dialog.showOpenDialog({
          title: '选择保存位置',
          defaultPath,
          properties: ['openDirectory', 'createDirectory']
        })
    if (result.canceled || result.filePaths.length === 0) return null
    return result.filePaths[0]
  })
}

import { BrowserWindow, dialog, ipcMain } from 'electron'
import { existsSync, readFileSync } from 'node:fs'
import { join } from 'node:path'
import {
  createExtension,
  deleteExtension,
  listExtensions,
  type Extension,
  updateExtension
} from '../services/store'
import {
  getLoadedExtensionIds,
  loadExtensionForAllContainers,
  openExtensionBrowserActionPopup,
  unloadExtensionFromAllContainers
} from '../services/extensions'

/**
 * 从扩展目录的 manifest.json 读取图标路径，返回绝对路径。
 * 优先选择 48px 图标，回退到最大可用尺寸。
 */
function readExtensionIcon(extensionPath: string): string | undefined {
  const manifestPath = join(extensionPath, 'manifest.json')
  if (!existsSync(manifestPath)) return undefined

  try {
    const manifest = JSON.parse(readFileSync(manifestPath, 'utf-8')) as {
      icons?: Record<string, string>
    }
    const icons = manifest.icons
    if (!icons) return undefined

    // 优先 48，然后 128、32、16
    for (const size of [48, 128, 32, 16]) {
      const iconPath = icons[String(size)]
      if (iconPath && existsSync(join(extensionPath, iconPath))) {
        return join(extensionPath, iconPath)
      }
    }

    // 回退：取最大的图标
    const sizes = Object.keys(icons)
      .map(Number)
      .sort((a, b) => b - a)
    if (sizes.length > 0) {
      const iconPath = icons[String(sizes[0])]
      if (iconPath && existsSync(join(extensionPath, iconPath))) {
        return join(extensionPath, iconPath)
      }
    }
    return undefined
  } catch {
    return undefined
  }
}

/**
 * 注册扩展相关 IPC 处理器。
 */
export function registerExtensionHandlers(): void {
  ipcMain.handle('extension:list', async (): Promise<Extension[]> => {
    const extensions = listExtensions()
    // 为缺少图标的扩展自动填充（兼容已有数据）
    for (const ext of extensions) {
      if (!ext.icon) {
        const icon = readExtensionIcon(ext.path)
        if (icon) {
          ext.icon = icon
          updateExtension(ext.id, { icon })
        }
      }
    }
    return extensions
  })

  ipcMain.handle('extension:select', async (event): Promise<Extension | null> => {
    console.log('[Extension IPC] extension:select called')

    const ownerWindow = BrowserWindow.fromWebContents(event.sender)
    const dialogOptions = {
      title: '选择 Chrome 扩展目录',
      properties: ['openDirectory', 'dontAddToRecent'] as const
    }

    const result = ownerWindow
      ? await dialog.showOpenDialog(ownerWindow, dialogOptions)
      : await dialog.showOpenDialog(dialogOptions)

    console.log('[Extension IPC] dialog result:', result)

    if (result.canceled || result.filePaths.length === 0) {
      return null
    }

    const extensionPath = result.filePaths[0]
    const manifestPath = join(extensionPath, 'manifest.json')
    if (!existsSync(manifestPath)) {
      throw new Error('所选目录不是有效的 Chrome 扩展，缺少 manifest.json')
    }

    let extensionName = 'Unknown Extension'
    try {
      const manifestContent = readFileSync(manifestPath, 'utf-8')
      const manifest = JSON.parse(manifestContent) as {
        name?: string
        short_name?: string
      }
      extensionName = manifest.name || manifest.short_name || extensionName
    } catch (error) {
      console.error('[Extension IPC] Failed to read manifest:', error)
    }

    const existedExtension = listExtensions().find((extension) => extension.path === extensionPath)
    if (existedExtension) {
      // 补充图标（兼容旧数据）
      if (!existedExtension.icon) {
        const icon = readExtensionIcon(extensionPath)
        if (icon) {
          existedExtension.icon = icon
          updateExtension(existedExtension.id, { icon })
        }
      }
      return existedExtension
    }

    return createExtension({
      name: extensionName,
      path: extensionPath,
      enabled: true,
      icon: readExtensionIcon(extensionPath)
    })
  })

  ipcMain.handle('extension:load', async (_event, extensionId: string): Promise<void> => {
    const extension = listExtensions().find((item) => item.id === extensionId)
    if (!extension) {
      console.error('[Extension:load] Extension not found:', extensionId)
      throw new Error(`扩展 ${extensionId} 不存在`)
    }

    await loadExtensionForAllContainers(extension)
  })

  ipcMain.handle('extension:unload', async (_event, extensionId: string): Promise<void> => {
    await unloadExtensionFromAllContainers(extensionId)
  })

  ipcMain.handle('extension:delete', async (_event, extensionId: string): Promise<void> => {
    await unloadExtensionFromAllContainers(extensionId)
    deleteExtension(extensionId)
  })

  ipcMain.handle(
    'extension:update',
    async (_event, id: string, data: Partial<Omit<Extension, 'id'>>): Promise<void> => {
      const extension = listExtensions().find((item) => item.id === id)
      if (!extension) {
        throw new Error(`扩展 ${id} 不存在`)
      }

      // 如果 `enabled` 状态发生变化，需要同步加载或卸载扩展
      if ('enabled' in data && data.enabled !== extension.enabled) {
        if (data.enabled) {
          // 启用：加载扩展
          await loadExtensionForAllContainers(extension)
        } else {
          // 禁用：卸载扩展
          await unloadExtensionFromAllContainers(id)
        }
      }

      updateExtension(id, data)
    }
  )

  ipcMain.handle('extension:getLoaded', async (): Promise<string[]> => {
    return getLoadedExtensionIds()
  })

  ipcMain.handle(
    'extension:openBrowserActionPopup',
    async (
      _event,
      containerId: string | null,
      extensionId: string,
      anchorRect: { x: number; y: number; width: number; height: number }
    ): Promise<void> => {
      openExtensionBrowserActionPopup(containerId, extensionId, anchorRect)
    }
  )
}

import { ipcMain, BrowserWindow, dialog, app, shell } from 'electron'
