import { ensureIconDir, getCachedIconPath, fetchAndCacheFavicon, getSiteIconsDir } from './services/favicon-cache'
import { electronApp, optimizer } from '@electron-toolkit/utils'

// 节流函数
function throttle<T extends (...args: any[]) => void>(fn: T, delay: number): T {
  let timer: NodeJS.Timeout | null = null
  return ((...args: Parameters<T>) => {
    if (timer) return
    timer = setTimeout(() => {
      fn(...args)
      timer = null
    }, delay)
  }) as T
}

// 在 app ready 之前设置 UA
setupUserAgent()

process.on('uncaughtException', (error) => {
  console.error('[Main] uncaughtException', {
    name: error.name,
    message: error.message,
    stack: error.stack
  })
})

process.on('unhandledRejection', (reason) => {
  const error = reason instanceof Error
    ? { name: reason.name, message: reason.message, stack: reason.stack }
    : { reason: String(reason) }
  console.error('[Main] unhandledRejection', error)
})

// 注册自定义协议，用于加载账号图标和扩展图标（必须在 app ready 前调用）
protocol.registerSchemesAsPrivileged([
  {
    scheme: 'account-icon',
    privileges: { bypassCSP: true, stream: true, supportFetchAPI: true }
  },
  {
    scheme: 'extension-icon',
    privileges: { bypassCSP: true, stream: true, supportFetchAPI: true }
  },
  {
    scheme: 'site-icon',
    privileges: { bypassCSP: true, stream: true, supportFetchAPI: true }
  },
  {
    scheme: 'screenshot',
    privileges: { bypassCSP: true, stream: true, supportFetchAPI: true }
  }
])

// 注册 sessionbox:// 深度链接协议
app.setAsDefaultProtocolClient('sessionbox')

if (process.platform === 'win32') {
  ensureWindowsBrowserRegistration()
}

/** 处理 sessionbox:// 协议 URL */
function handleProtocolUrl(url: string): void {
  try {
    const parsed = new URL(url)
    if (parsed.host === 'openContainer') {
      const containerId = parsed.searchParams.get('id')
      if (!containerId) return
      const win = BrowserWindow.getAllWindows()[0]
      if (win) {
        if (win.isMinimized()) win.restore()
        win.focus()
        win.webContents.send('open-container', containerId)
      }
    }
  } catch (e) {
    console.error('协议 URL 解析失败', e)
  }
}

/** 处理外部 http/https URL（默认浏览器功能） */
function handleExternalUrl(url: string): void {
  const win = BrowserWindow.getAllWindows()[0]
  if (!win) return
  if (win.isMinimized()) win.restore()
  win.focus()
  // 通知渲染进程使用默认容器打开新 tab
  win.webContents.send('on:open-external-url', url)
}

// 单实例锁：防止多开，同时用于接收深度链接
const gotTheLock = app.requestSingleInstanceLock()
if (!gotTheLock) {
  app.quit()
} else {
  // Windows: 协议 URL 通过 second-instance 事件传入（应用已在运行时）
  app.on('second-instance', (_e, argv) => {
    const protocolUrl = argv.find((arg) => arg.startsWith('sessionbox://'))
    if (protocolUrl) {
      handleProtocolUrl(protocolUrl)
      return
    }
    // 处理外部 http/https 链接（默认浏览器功能）
    const externalUrl = argv.find((arg) => arg.startsWith('http://') || arg.startsWith('https://'))
    if (externalUrl) handleExternalUrl(externalUrl)
  })

  // macOS: 外部 URL 通过 open-url 事件传入
  app.on('open-url', (_e, url: string) => {
    if (url.startsWith('http://') || url.startsWith('https://')) {
      handleExternalUrl(url)
    } else if (url.startsWith('sessionbox://')) {
      handleProtocolUrl(url)
    }
  })

  let isQuitting = false

  app.on('before-quit', () => {
    isQuitting = true
    mcpServerService.stop().catch((error) => {
      console.error('[Main] Failed to stop MCP server:', error)
    })
    pluginManager.shutdown()
    trayWindowManager.destroyAll()
  })

  function createWindow(): void {
    const iconPath = app.isPackaged
      ? join(process.resourcesPath, 'icon.png')
      : join(__dirname, '../../resources/icon.png')

    // 加载窗口状态
    const windowState = getWindowState()

    const mainWindow = new BrowserWindow({
      x: windowState.x,
      y: windowState.y,
      width: windowState.width,
      height: windowState.height,
      show: false,
      autoHideMenuBar: true,
      frame: false,
      transparent: true,
      icon: nativeImage.createFromPath(iconPath),
      webPreferences: {
        preload: join(__dirname, '../preload/index.js'),
        sandbox: false
      }
    })

    // 如果保存的状态是最大化，则恢复
    if (windowState.isMaximized) {
      mainWindow.maximize()
    }

    // 初始化 WebContentsView 管理器
    webviewManager.setMainWindow(mainWindow)

    // 暴露到 global 以便浏览器交互 IPC 处理器访问
    ;(global as any).__webviewManager = webviewManager

    // 初始化自动更新器主窗口引用
    getAutoUpdater().setMainWindow(mainWindow)

    mainWindow.on('ready-to-show', () => {
      mainWindow.show()
    })

    // 通知渲染进程窗口最大化状态变化
    mainWindow.on('maximize', () => {
      mainWindow.webContents.send('on:window:maximized')
      // 同步保存最大化状态
      const state = getWindowState()
      setWindowState({ ...state, isMaximized: true })
    })
    mainWindow.on('unmaximize', () => {
      mainWindow.webContents.send('on:window:unmaximized')
      const state = getWindowState()
      setWindowState({ ...state, isMaximized: false })
    })

    // 节流保存窗口状态（位置和大小变化时）
    const saveWindowBounds = throttle(() => {
      if (mainWindow.isDestroyed() || mainWindow.isMaximized()) return
      const bounds = mainWindow.getBounds()
      const state = getWindowState()
      setWindowState({
        ...state,
        x: bounds.x,
        y: bounds.y,
        width: bounds.width,
        height: bounds.height
      })
    }, 500)

    mainWindow.on('resize', saveWindowBounds)
    mainWindow.on('move', saveWindowBounds)

    // 窗口关闭时隐藏到托盘或直接退出（取决于用户设置）
    mainWindow.on('close', (e) => {
      if (!isQuitting) {
        const shouldMinimize = getMinimizeOnClose()
        if (shouldMinimize) {
          e.preventDefault()
          if (!mainWindow.isMaximized()) {
            const bounds = mainWindow.getBounds()
            const state = getWindowState()
            setWindowState({
              ...state,
              x: bounds.x,
              y: bounds.y,
              width: bounds.width,
              height: bounds.height
            })
          }
          mainWindow.hide()
          return
        }
        // minimizeOnClose 为 false 时，允许默认关闭行为
        // isQuitting 仍为 false，但窗口关闭后会触发 window-all-closed
      }
      // 真正退出时保存状态
      if (!mainWindow.isMaximized()) {
        const bounds = mainWindow.getBounds()
        const state = getWindowState()
        setWindowState({
          ...state,
          x: bounds.x,
          y: bounds.y,
          width: bounds.width,
          height: bounds.height
        })
      }
    })

    // 窗口已销毁后清理 WebContentsView
    mainWindow.on('closed', () => {
      webviewManager.destroyAll()
    })

    // 拦截本地快捷键（禁用 Ctrl+R 刷新、Ctrl+W 关闭等系统默认行为）
    mainWindow.webContents.on('before-input-event', (event, input) => {
      if (handleBeforeInputEvent(input, mainWindow.webContents)) {
        event.preventDefault()
      }
    })

    // 首次启动时处理协议 URL（例如从桌面快捷方式启动）
    const protocolUrl = process.argv.find((arg) => arg.startsWith('sessionbox://'))
    if (protocolUrl) {
      mainWindow.webContents.once('did-finish-load', () => {
        handleProtocolUrl(protocolUrl)
      })
    }

    // 首次启动时处理外部 http/https 链接（默认浏览器功能）
    const externalUrl = process.argv.find((arg) => arg.startsWith('http://') || arg.startsWith('https://'))
    if (externalUrl) {
      mainWindow.webContents.once('did-finish-load', () => {
        handleExternalUrl(externalUrl)
      })
    }

    if (process.env.ELECTRON_RENDERER_URL) {
      mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL)
    } else {
      mainWindow.loadFile(join(__dirname, '../renderer/index.html'))
    }
  }

  app.whenReady().then(() => {
    electronApp.setAppUserModelId('com.session-box')

    ensureWindowsBrowserRegistration()

    // 迁移 bookmark/password/workflow 数据到独立 JsonStore
    migrateBookmarksAndPasswords()
    migrateWorkflows()

    app.on('browser-window-created', (_, window) => {
      optimizer.watchWindowShortcuts(window)
    })

    // 注册所有 IPC 处理器
    registerIpcHandlers()
    registerDownloadIpcHandlers()
    registerExecutionLogIpcHandlers()
    registerWorkflowVersionIpcHandlers()

    // 初始化插件系统
    pluginManager.loadAll()

    // 初始化标签冻结定时器
    webviewManager.setFreezeMinutes(getTabFreezeMinutes())

    // 注册 account-icon:// 协议，从 userData/container-icons/ 目录提供文件
    const iconDir = join(app.getPath('userData'), 'container-icons')
    protocol.handle('account-icon', (request) => {
      const url = new URL(request.url)
      const fileName = decodeURIComponent(url.host + url.pathname).replace(/\/+$/, '')
      return net.fetch(`file://${join(iconDir, fileName).replace(/\\/g, '/')}`)
    })

    // 注册 extension-icon:// 协议，通过扩展 ID 查找并返回扩展图标文件
    protocol.handle('extension-icon', (request) => {
      const extensionId = decodeURIComponent(request.url.replace('extension-icon://', ''))
      const extension = listExtensions().find((e) => e.id === extensionId)
      if (!extension?.icon) return new Response('Not found', { status: 404 })
      return net.fetch(`file://${extension.icon.replace(/\\/g, '/')}`)
    })

    // 注册 screenshot:// 协议，从 userData/ai-screenshots/ 提供截图文件
    const screenshotDir = join(app.getPath('userData'), 'ai-screenshots')
    protocol.handle('screenshot', (request) => {
      const filename = decodeURIComponent(request.url.replace('screenshot://', '')).replace(/\/+$/, '')
      if (!filename) return new Response('Bad request', { status: 400 })
      return net.fetch(`file://${join(screenshotDir, filename).replace(/\\/g, '/')}`)
    })

    // 注册 site-icon:// 协议，从本地缓存提供网站图标，缓存未命中时自动下载
    ensureIconDir()
    protocol.handle('site-icon', async (request) => {
      // 剥离查询参数（?v=xxx 用于浏览器缓存失效）
      const raw = decodeURIComponent(request.url.replace('site-icon://', '')).replace(/\/+$/, '')
      const domain = raw.split('?')[0]
      if (!domain) return new Response('Bad request', { status: 400 })

      // 优先从本地缓存查找
      const cachedPath = getCachedIconPath(domain)
      if (cachedPath) {
        return net.fetch(`file://${cachedPath.replace(/\\/g, '/')}`)
      }

      // 缓存未命中，按策略下载并缓存（始终返回有效路径）
      const filePath = await fetchAndCacheFavicon(domain)
      return net.fetch(`file://${filePath.replace(/\\/g, '/')}`)
    })

    // 注册已知第三方协议的空处理器，防止网站唤起外部应用时系统弹出"打开方式"对话框
    for (const scheme of BLOCKED_SCHEMES) {
      protocol.handle(scheme, () => new Response(null, { status: 204 }))
    }

    createWindow()

    // 初始化系统托盘（createWindow 内部创建 mainWindow，需要在这里获取引用）
    const mainWindow = BrowserWindow.getAllWindows()[0]
    if (mainWindow) {
      trayManager.init(mainWindow)
      pluginManager.setMainWindow(mainWindow)
    }

    // 注册全局快捷键
    registerGlobalShortcuts()

    // 启动 MCP Server（如果已启用）
    if (getMcpEnabled()) {
      mcpServerService.start().catch((error) => {
        console.error('[Main] Failed to start MCP server:', error)
      })
    }

    // 启动 3 秒后自动检查更新
    setTimeout(() => {
      const autoUpdater = getAutoUpdater()
      autoUpdater.initUpdateSource()
      console.log('[Main] 开始检查更新...')
      autoUpdater.checkForUpdates()
    }, 3000)

    app.on('activate', () => {
      if (BrowserWindow.getAllWindows().length === 0) createWindow()
    })
  })

  app.on('window-all-closed', () => {
    unregisterGlobalShortcuts()
    // 当 minimizeOnClose 关闭时，窗口关闭即退出应用
    if (!getMinimizeOnClose()) {
      app.quit()
    }
    // 最小化到托盘模式：用户通过 Tray 菜单退出
  })
}

import { BrowserWindow, app, webContents } from 'electron'
import { join } from 'path'
import { mkdirSync, writeFileSync } from 'fs'
import { getAIProvider, listTabs, createTab, listGroups, listPages, listWorkspaces, getPageById, getGroupById } from './store'
import { webviewManager } from './webview-manager'
import { extractPageSummary, extractPageMarkdown, extractInteractiveNodes, extractInteractiveNodeDetail } from './page-extractor'
import { writeSkill, readSkill, listSkills, searchSkill } from './skill-store'
import {
  buildCategoryListResponse,
  buildToolDetailResponse,
  buildToolListResponse,
  isBrowserBusinessToolName,
} from '../../src/lib/agent/tools'
import { dispatchWorkflowTool, rejectPendingRendererToolsForRequest } from './workflow-tool-dispatcher'

interface ProxyRequest {
  _requestId: string
  providerId: string
  modelId: string
  system?: string
  messages: Array<{ role: string; content: string | Array<Record<string, unknown>> }>
  tools?: Array<Record<string, unknown>>
  stream: boolean
  maxTokens?: number
  thinking?: { type: 'enabled'; budgetTokens: number }
  targetTabId?: string
  enabledToolNames?: string[]
  _mode?: string
  _workflowId?: string
}

/** 可重试的 HTTP 状态码（服务过载、限流、临时故障） */
const RETRYABLE_STATUS_CODES = new Set([429, 529, 500, 502, 503, 504])
const MAX_RETRIES = 3
const INITIAL_RETRY_DELAY_MS = 2000

/** 活跃请求的 AbortController 映射，供外部中止 */
export const activeRequests = new Map<string, AbortController>()

/**
 * 判断错误是否可重试。
 * 529 (overloaded) 和 429 (rate_limit) 是典型场景。
 */
function isRetryableError(status: number): boolean {
  return RETRYABLE_STATUS_CODES.has(status)
}

/**
 * 延迟指定毫秒数（指数退避）。
 */
function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value)
}

interface ImageToolContent {
  mediaType: string
  data: string
  width: number
  height: number
}

function getImageToolContent(result: unknown): ImageToolContent | null {
  if (!isRecord(result)) return null
  if ('_isImageContent' in result) return result as unknown as ImageToolContent

  const data = result.data
  if (!isRecord(data)) return null

  const nestedResult = data.result
  if (isRecord(nestedResult) && '_isImageContent' in nestedResult) {
    return nestedResult as unknown as ImageToolContent
  }

  return null
}

/**
 * 将渲染进程的聊天请求代理到 LLM 供应商 API。
 * API Key 仅在主进程内存中组装，不暴露给渲染进程。
 * 支持 tool_use 多轮循环：LLM 请求调用工具 → 主进程执行 → 结果回传 → 继续对话。
 */
export async function proxyChatCompletions(
  mainWindow: BrowserWindow,
  params: ProxyRequest,
): Promise<void> {
  const { _requestId, providerId, modelId, system, messages, tools, stream, maxTokens, thinking, targetTabId, enabledToolNames, _mode, _workflowId } = params

  // 创建 AbortController 并注册到全局映射
  const abortController = new AbortController()
  activeRequests.set(_requestId, abortController)

  const send = (channel: string, data: unknown) => {
    if (!mainWindow.isDestroyed()) {
      mainWindow.webContents.send(channel, data)
    }
  }

  try {
    const provider = getAIProvider(providerId)
    if (!provider) {
      send('on:chat:error', { requestId: _requestId, error: `Provider not found: ${providerId}` })
      return
    }
    if (!provider.apiKey) {
      send('on:chat:error', { requestId: _requestId, error: `Provider has no API key: ${providerId}` })
      return
    }

    const apiUrl = `${provider.apiBase.replace(/\/$/, '')}/v1/messages`
    const MAX_TOOL_ROUNDS = 100

    // 多轮对话循环：LLM 可能多次请求 tool_use
    let currentMessages = [...messages]
    let cumulativeUsage = { inputTokens: 0, outputTokens: 0 }
    let contentBlockOffset = 0

    for (let round = 0; round < MAX_TOOL_ROUNDS; round++) {
      console.log(`[ai-proxy] round ${round + 1}, messages count: ${currentMessages.length}`)

      const body: Record<string, unknown> = {
        model: modelId,
        messages: currentMessages,
        max_tokens: maxTokens ?? 4096,
        stream: true,
      }
      if (system) {
        body.system = system
      }
      if (tools && tools.length > 0) {
        body.tools = tools
      }
      if (thinking) {
        body.thinking = thinking
        if (!maxTokens || maxTokens < (thinking.budgetTokens + 1024)) {
          body.max_tokens = (thinking.budgetTokens + 4096)
        }
      }

      let response: Response | null = null
      let lastErrorText = ''

      for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
        response = await fetch(apiUrl, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'x-api-key': provider.apiKey,
            'anthropic-version': '2023-06-01',
            'anthropic-dangerous-direct-browser-access': 'true',
          },
          body: JSON.stringify(body),
          signal: abortController.signal,
        })

        if (response.ok) break

        lastErrorText = await response.text()

        if (attempt < MAX_RETRIES && isRetryableError(response.status)) {
          const retryDelay = INITIAL_RETRY_DELAY_MS * Math.pow(2, attempt)
          console.warn(
            `[ai-proxy] API error ${response.status} (attempt ${attempt + 1}/${MAX_RETRIES + 1}), retrying in ${retryDelay}ms...`,
          )
          send('on:chat:retry', {
            requestId: _requestId,
            attempt: attempt + 1,
            maxRetries: MAX_RETRIES,
            delayMs: retryDelay,
            status: response.status,
            error: lastErrorText,
          })
          await delay(retryDelay)
          continue
        }

        // 不可重试或已耗尽重试次数
        send('on:chat:error', { requestId: _requestId, error: `API error ${response.status}: ${lastErrorText}` })
        return
      }

      if (!response || !response.body) {
        send('on:chat:error', { requestId: _requestId, error: 'No response body' })
        return
      }

      // 解析 SSE 流，累积完整的 assistant message
      const parsed = await parseSSEStream(response.body, send, _requestId, cumulativeUsage, contentBlockOffset)

      console.log(`[ai-proxy] round ${round + 1} done, stop_reason: ${parsed.stopReason}, tool_calls: ${parsed.toolCalls.length}`)

      // 累加本轮 content block 数量，作为下轮 index 偏移
      contentBlockOffset += parsed.blockCount

      // 没有 tool_use，正常结束
      if (parsed.stopReason !== 'tool_use' || parsed.toolCalls.length === 0) {
        send('on:chat:done', { requestId: _requestId, usage: cumulativeUsage })
        return
      }

      // === 工具执行阶段 ===
      console.log(`[ai-proxy] executing ${parsed.toolCalls.length} tool call(s)...`)

      // 构造 assistant message（含文本 + tool_use blocks）
      const assistantContent: Array<Record<string, unknown>> = []
      if (parsed.textContent) {
        assistantContent.push({ type: 'text', text: parsed.textContent })
      }
      for (const tc of parsed.toolCalls) {
        assistantContent.push({
          type: 'tool_use',
          id: tc.id,
          name: tc.name,
          input: tc.args,
        })
      }

      // 执行每个工具，收集 tool_result
      const toolResults: Array<Record<string, unknown>> = []
      for (const tc of parsed.toolCalls) {
        console.log(`[ai-proxy] executing tool: ${tc.name}, args: ${JSON.stringify(tc.args)}`)
        let result: any
        if (_mode === 'workflow' && _workflowId) {
          result = await dispatchWorkflowTool(
            mainWindow,
            _requestId,
            tc.id,
            tc.name,
            tc.args,
            _workflowId,
          )
        } else {
          result = await executeTool(tc.name, tc.args, targetTabId, enabledToolNames)
        }

        // 构建工具结果内容：图片需要结构化数组格式
        let toolResultContent: string | Array<Record<string, unknown>>
        const img = getImageToolContent(result)
        if (img) {
          toolResultContent = [
            { type: 'text', text: `Screenshot captured (${img.width}x${img.height})` },
            { type: 'image', source: { type: 'base64', media_type: img.mediaType, data: img.data } },
          ]
          console.log(`[ai-proxy] tool ${tc.name} result: screenshot ${img.width}x${img.height}`)
        } else {
          toolResultContent = typeof result === 'string' ? result : JSON.stringify(result)
          console.log(`[ai-proxy] tool ${tc.name} result: ${(toolResultContent as string).slice(0, 200)}`)
        }

        // 通知渲染进程：工具执行完成 + 结果
        // 安全序列化：部分工具可能返回不可直接克隆的对象（如 electron-store 的代理对象）
        const safeResult = typeof result === 'string'
          ? result
          : JSON.parse(JSON.stringify(result))
        send('on:chat:tool-result', {
          requestId: _requestId,
          toolUseId: tc.id,
          name: tc.name,
          result: safeResult,
        })

        toolResults.push({
          type: 'tool_result',
          tool_use_id: tc.id,
          content: toolResultContent,
        })
      }

      // 把 assistant message + tool_result 追加到消息历史，进入下一轮
      currentMessages.push({ role: 'assistant', content: assistantContent })
      currentMessages.push({ role: 'user', content: toolResults })
    }

    // 超过最大轮次，强制结束
    console.warn(`[ai-proxy] reached max tool rounds (${MAX_TOOL_ROUNDS}), stopping`)
    send('on:chat:done', { requestId: _requestId })
  } catch (error) {
    // AbortError 表示用户主动中止，静默处理
    if (error instanceof DOMException && error.name === 'AbortError') {
      console.log(`[ai-proxy] request ${_requestId} aborted by user`)
      return
    }
    if (error instanceof Error && error.name === 'AbortError') {
      console.log(`[ai-proxy] request ${_requestId} aborted by user`)
      return
    }
    send('on:chat:error', {
      requestId: _requestId,
      error: error instanceof Error ? error.message : String(error),
    })
  } finally {
    rejectPendingRendererToolsForRequest(
      _requestId,
      new Error('聊天请求已结束，渲染进程工具等待已取消'),
    )
    activeRequests.delete(_requestId)
  }
}

/**
 * 根据 Anthropic SSE event type 转发到对应的 IPC 通道
 */
function forwardSSEEvent(
  send: (channel: string, data: unknown) => void,
  requestId: string,
  event: Record<string, unknown>,
  indexOffset = 0,
): void {
  const type = event.type as string

  switch (type) {
    case 'content_block_delta': {
      const delta = event.delta as Record<string, unknown> | undefined
      if (delta?.type === 'text_delta') {
        send('on:chat:chunk', { requestId, token: delta.text })
      } else if (delta?.type === 'thinking_delta') {
        send('on:chat:thinking', { requestId, content: delta.thinking, index: (event.index as number) + indexOffset })
      } else if (delta?.type === 'input_json_delta' && typeof delta.partial_json === 'string') {
        send('on:chat:tool-call-args-delta', { requestId, index: event.index, delta: delta.partial_json })
      }
      break
    }
    case 'content_block_start': {
      const contentBlock = event.content_block as Record<string, unknown> | undefined
      if (contentBlock?.type === 'tool_use') {
        send('on:chat:tool-call', {
          requestId,
          toolCall: {
            id: contentBlock.id,
            name: contentBlock.name,
            args: {},
            status: 'running',
            startedAt: Date.now(),
          },
        })
      }
      break
    }
    case 'content_block_stop': {
      const index = event.index as number
      send('on:chat:tool-call-update', { requestId, index, status: 'completed', completedAt: Date.now() })
      break
    }
    case 'message_delta': {
      const delta = event.delta as Record<string, unknown> | undefined
      if (delta?.stop_reason) {
        send('on:chat:stop-reason', { requestId, stopReason: delta.stop_reason })
      }
      break
    }
    case 'error': {
      send('on:chat:error', { requestId, error: event.error })
      break
    }
  }
}

// ===== SSE 流解析（累积 tool_use 信息） =====

interface ParsedToolCall {
  id: string
  name: string
  args: Record<string, unknown>
}

interface ParsedStream {
  textContent: string
  toolCalls: ParsedToolCall[]
  stopReason: string | null
}

/**
 * 解析完整 SSE 流，同时转发事件到渲染进程并累积 tool_use 信息。
 * cumulativeUsage 用于跨多轮 tool_use 循环累积 token 用量。
 */
async function parseSSEStream(
  body: NodeJS.ReadableStream,
  send: (channel: string, data: unknown) => void,
  requestId: string,
  cumulativeUsage: { inputTokens: number; outputTokens: number },
  indexOffset = 0,
): Promise<ParsedStream & { blockCount: number }> {
  const reader = body.getReader()
  const decoder = new TextDecoder()
  let buffer = ''

  let textContent = ''
  let stopReason: string | null = null
  let maxIndex = -1

  // tool_use 累积状态
  // content_block 的 index 并不总是从 0 开始（前面可能有 text block），
  // 所以用 index → toolCalls 数组下标 的映射来关联
  const toolCalls: ParsedToolCall[] = []
  const toolJsonBuffers = new Map<number, { callIndex: number; json: string }>()

  while (true) {
    const { done, value } = await reader.read()
    if (done) break

    buffer += decoder.decode(value, { stream: true })
    const lines = buffer.split('\n')
    buffer = lines.pop() ?? ''

    for (const line of lines) {
      if (!line.startsWith('data: ')) continue
      const data = line.slice(6).trim()
      if (data === '[DONE]') continue

      let event: Record<string, unknown>
      try { event = JSON.parse(data) } catch { continue }

      const type = event.type as string

      // 转发事件给渲染进程
      forwardSSEEvent(send, requestId, event, indexOffset)

      // 追踪最大 block index
      if (typeof event.index === 'number') {
        maxIndex = Math.max(maxIndex, event.index)
      }

      // 累积文本 & tool_use 参数 JSON（都在 content_block_delta 事件中）
      if (type === 'content_block_delta') {
        const delta = event.delta as Record<string, unknown> | undefined
        if (delta?.type === 'text_delta' && typeof delta.text === 'string') {
          textContent += delta.text
        }
        // Anthropic 格式：delta.type === 'input_json_delta'，字段为 partial_json
        if (delta?.type === 'input_json_delta' && typeof delta.partial_json === 'string') {
          const idx = event.index as number
          const buf = toolJsonBuffers.get(idx)
          if (buf) {
            buf.json += delta.partial_json
          }
        }
      }

      // 累积 tool_use 开始
      if (type === 'content_block_start') {
        const cb = event.content_block as Record<string, unknown> | undefined
        if (cb?.type === 'tool_use') {
          const idx = event.index as number
          const callIndex = toolCalls.length
          toolCalls.push({ id: cb.id as string, name: cb.name as string, args: {} })
          toolJsonBuffers.set(idx, { callIndex, json: '' })
        }
      }

      // tool_use 参数结束 → 解析 JSON 并通知渲染进程
      if (type === 'content_block_stop') {
        const idx = event.index as number
        const buf = toolJsonBuffers.get(idx)
        if (buf) {
          try {
            const parsed = JSON.parse(buf.json || '{}')
            toolCalls[buf.callIndex].args = parsed
            // 将完整 args 回传给渲染进程
            send('on:chat:tool-call-args', {
              requestId,
              toolUseId: toolCalls[buf.callIndex].id,
              args: parsed,
            })
          } catch {
            console.error(`[ai-proxy] failed to parse tool args JSON: ${buf.json}`)
          }
          toolJsonBuffers.delete(idx)
        }
      }

      // stop_reason & usage
      if (type === 'message_delta') {
        const delta = event.delta as Record<string, unknown> | undefined
        if (delta?.stop_reason) {
          stopReason = delta.stop_reason as string
        }
        const usage = event.usage as Record<string, unknown> | undefined
        if (usage && typeof usage.output_tokens === 'number') {
          cumulativeUsage.outputTokens += usage.output_tokens
          send('on:chat:usage', { requestId, ...cumulativeUsage })
        }
      }

      // message_start 携带本輪 input_tokens
      if (type === 'message_start') {
        const msg = event.message as Record<string, unknown> | undefined
        const usage = msg?.usage as Record<string, unknown> | undefined
        if (usage && typeof usage.input_tokens === 'number') {
          cumulativeUsage.inputTokens += usage.input_tokens
          send('on:chat:usage', { requestId, ...cumulativeUsage })
        }
      }
    }
  }

  return { textContent, toolCalls, stopReason, blockCount: maxIndex + 1 }
}

// ===== 工具执行（主进程内直接调用 store / webviewManager） =====

/**
 * 根据工具名在主进程内执行对应操作，返回结果。
 */
export async function executeTool(
  name: string,
  args: Record<string, unknown>,
  targetTabId?: string,
  enabledToolNames?: string[],
): Promise<unknown> {
  console.log(`[ai-proxy executeTool] name=${name}, args=${JSON.stringify(args)}`)

  try {
    switch (name) {
      case 'list_categories': {
        return buildCategoryListResponse()
      }

      case 'list_tools_by_category': {
        const category = args.category as string
        if (!category) return { error: 'category is required' }
        return buildToolListResponse(category, enabledToolNames)
      }

      case 'get_tool_detail': {
        const toolName = (args.tool_name || args.toolName || args.name) as string
        if (!toolName) return { error: 'tool_name is required' }
        return buildToolDetailResponse(toolName, enabledToolNames)
      }

      case 'execute_tool': {
        const toolName = (args.tool_name || args.toolName || args.name) as string
        const toolArgs = isRecord(args.args) ? args.args : {}

        if (!toolName) return { error: 'tool_name is required' }
        if (!isBrowserBusinessToolName(toolName)) return { error: `Unknown tool: ${toolName}` }
        if (enabledToolNames && !enabledToolNames.includes(toolName)) {
          return { error: `Tool is disabled: ${toolName}` }
        }

        const result = await executeTool(toolName, toolArgs, targetTabId, enabledToolNames)
        return {
          stage: 'execute',
          need_next: false,
          next_action: 'none',
          data: {
            tool: toolName,
            result,
          },
          message: '工具执行完成。',
        }
      }

      case 'list_tabs': {
        const tabs = listTabs()
        const activeTabId = webviewManager.getActiveTabId()
        const result = tabs.map((tab) => {
          const viewInfo = webviewManager.getViewInfo(tab.id)
          const page = tab.pageId ? getPageById(tab.pageId) : undefined
          const group = page?.groupId ? getGroupById(page.groupId) : undefined
          return {
            tabId: tab.id,
            pageId: tab.pageId,
            title: tab.title,
            url: viewInfo?.url ?? tab.url,
            isActive: tab.id === activeTabId,
            isFrozen: webviewManager.isFrozen(tab.id),
            pinned: tab.pinned,
            muted: tab.muted,
            groupName: group?.name,
          }
        })
        console.log(`[ai-proxy executeTool] list_tabs returning ${result.length} tabs`)
        return result
      }

      case 'list_groups': {
        return listGroups()
      }

      case 'list_workspaces': {
        return listWorkspaces()
      }

      case 'list_pages': {
        return listPages()
      }

      case 'get_active_tab': {
        const activeTabId = targetTabId || webviewManager.getActiveTabId()
        if (!activeTabId) {
          return { error: '没有选中的标签页' }
        }
        const viewInfo = webviewManager.getViewInfo(activeTabId)
        const tabs = listTabs()
        const tab = tabs.find((t) => t.id === activeTabId)
        if (!tab) {
          return { error: `标签页 ${activeTabId} 不存在` }
        }
        const page = tab.pageId ? getPageById(tab.pageId) : undefined
        const group = page?.groupId ? getGroupById(page.groupId) : undefined
        return {
          tabId: tab.id,
          pageId: tab.pageId,
          title: tab.title,
          url: viewInfo?.url ?? tab.url,
          isFrozen: webviewManager.isFrozen(tab.id),
          groupName: group?.name,
          containerId: page?.containerId,
        }
      }

      case 'create_tab': {
        const url = (args.url as string) || 'https://www.baidu.com'
        const active = args.active !== false // 默认激活
        const pageId = (args.pageId as string) || null
        let workspaceId = args.workspaceId as string | undefined
        const tabs = listTabs()

        // 未指定工作区时，从当前激活标签页反推
        if (!workspaceId) {
          const activeTabId = webviewManager.getActiveTabId()
          if (activeTabId) {
            const activeTab = tabs.find((t) => t.id === activeTabId)
            if (activeTab?.pageId) {
              const page = getPageById(activeTab.pageId)
              if (page?.groupId) {
                const group = getGroupById(page.groupId)
                workspaceId = group?.workspaceId
              }
            }
          }
        }

        const order = tabs.reduce((max, t) => Math.max(max, t.order), -1) + 1
        const mainWindow = webviewManager.getMainWindow()

        if (pageId) {
          const page = getPageById(pageId)
          if (!page) return { error: `页面 ${pageId} 不存在` }
          const tabUrl = url || page.url
          const tab = createTab({ pageId, title: page.name, url: tabUrl, order })
          webviewManager.registerPendingView(tab.id, pageId, page.containerId || '', tabUrl)
          mainWindow?.webContents.send('on:tab:created', tab)
          if (active) webviewManager.switchView(tab.id)
          return {
            success: true,
            mode: 'tab',
            tabId: tab.id,
            pageId,
            containerId: page.containerId || undefined,
            title: tab.title,
            url: tabUrl,
            workspaceId,
          }
        }

        const containerId = (args.containerId as string) || ''
        const tab = createTab({
          pageId: '',
          title: '新标签页',
          url,
          order,
          workspaceId
        })
        webviewManager.registerPendingView(tab.id, '', containerId, url)
        mainWindow?.webContents.send('on:tab:created', tab)
        if (active) webviewManager.switchView(tab.id)
        return {
          success: true,
          mode: 'tab',
          tabId: tab.id,
          pageId: '',
          containerId: containerId || undefined,
          title: tab.title,
          url,
          workspaceId,
        }
      }

      case 'navigate_tab': {
        const tabId = (args.tabId as string) || webviewManager.getActiveTabId()
        const url = args.url as string
        if (!tabId || !url) return { error: 'tabId and url are required' }
        webviewManager.navigate(tabId, url)
        return { success: true, tabId, url }
      }

      // ===== 窗口操作工具 =====

      case 'create_window': {
        const url = (args.url as string) || 'about:blank'
        const pageId = (args.pageId as string) || null
        const containerId = (args.containerId as string) || ''
        const title = (args.title as string) || (pageId ? (getPageById(pageId)?.name ?? '新窗口') : '新窗口')
        const width = (args.width as number) || 1280
        const height = (args.height as number) || 800

        const resolvedContainerId = pageId
          ? (getPageById(pageId)?.containerId || '')
          : containerId
        const partition = resolvedContainerId
          ? `persist:container-${resolvedContainerId}`
          : undefined

        const win = new BrowserWindow({
          width,
          height,
          show: false,
          autoHideMenuBar: true,
          title,
          webPreferences: {
            partition,
            sandbox: false,
          },
        })
        win.loadURL(url)
        win.once('ready-to-show', () => win.show())
        return {
          success: true,
          windowId: win.id,
          title,
          url,
          containerId: resolvedContainerId || undefined,
        }
      }

      case 'navigate_window': {
        const windowId = args.windowId as number | undefined
        const url = args.url as string
        if (windowId == null || !url) return { error: 'windowId and url are required' }
        const win = BrowserWindow.getAllWindows().find(w => w.id === windowId)
        if (!win || win.isDestroyed()) return { error: `Window ${windowId} not found` }
        void win.webContents.loadURL(url)
        return { success: true, windowId, url }
      }

      case 'close_window': {
        const windowId = args.windowId as number | undefined
        if (windowId == null) return { error: 'windowId is required' }
        const win = BrowserWindow.getAllWindows().find(w => w.id === windowId)
        if (!win || win.isDestroyed()) return { error: `Window ${windowId} not found` }
        win.close()
        return { success: true, windowId }
      }

      case 'list_windows': {
        return BrowserWindow.getAllWindows().map(w => ({
          windowId: w.id,
          title: w.getTitle(),
          url: w.webContents.getURL(),
          width: w.getBounds().width,
          height: w.getBounds().height,
          isMaximized: w.isMaximized(),
          isMain: w === webviewManager.getMainWindow(),
        }))
      }

      case 'focus_window': {
        const windowId = args.windowId as number | undefined
        if (windowId == null) return { error: 'windowId is required' }
        const win = BrowserWindow.getAllWindows().find(w => w.id === windowId)
        if (!win || win.isDestroyed()) return { error: `Window ${windowId} not found` }
        if (win.isMinimized()) win.restore()
        win.focus()
        return { success: true, windowId }
      }

      case 'screenshot_window': {
        const windowId = args.windowId as number | undefined
        if (windowId == null) return { error: 'windowId is required' }
        const win = BrowserWindow.getAllWindows().find(w => w.id === windowId)
        if (!win || win.isDestroyed()) return { error: `Window ${windowId} not found` }
        try {
          const image = await win.webContents.capturePage()
          if (image.isEmpty()) return { error: 'Window content is empty' }
          const jpeg = image.toJPEG(80)
          const size = image.getSize()

          const filename = `screenshot-window-${windowId}-${Date.now()}.jpg`
          const screenshotDir = join(app.getPath('userData'), 'ai-screenshots')
          mkdirSync(screenshotDir, { recursive: true })
          writeFileSync(join(screenshotDir, filename), jpeg)

          const base64 = jpeg.toString('base64')
          return {
            _isImageContent: true,
            url: `screenshot://${filename}`,
            mediaType: 'image/jpeg',
            data: base64,
            width: size.width,
            height: size.height,
          }
        } catch (err) {
          return { error: `Screenshot failed: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      case 'get_window_detail': {
        const windowId = args.windowId as number | undefined
        if (windowId == null) return { error: 'windowId is required' }
        const win = BrowserWindow.getAllWindows().find(w => w.id === windowId)
        if (!win || win.isDestroyed()) return { error: `Window ${windowId} not found` }
        const bounds = win.getBounds()
        return {
          windowId: win.id,
          title: win.getTitle(),
          url: win.webContents.getURL(),
          bounds,
          isMaximized: win.isMaximized(),
          isMinimized: win.isMinimized(),
          isFullScreen: win.isFullScreen(),
          isFocused: win.isFocused(),
          isMain: win === webviewManager.getMainWindow(),
        }
      }

      case 'switch_tab': {
        const tabId = args.tabId as string
        if (!tabId) return { error: 'tabId is required' }
        webviewManager.switchView(tabId)
        return { success: true, tabId }
      }

      case 'close_tab': {
        const tabId = args.tabId as string
        if (!tabId) return { error: 'tabId is required' }
        webviewManager.destroyView(tabId)
        return { success: true, tabId }
      }

      // 浏览器交互工具（需要 CDP / executeJavaScript）
      case 'click_element': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        if (!args.selector || typeof args.selector !== 'string') return { error: 'selector is required' }
        const selector = args.selector as string
        await wc.executeJavaScript(`document.querySelector('${cssEscape(selector)}')?.click()`)
        return { success: true }
      }

      case 'input_text': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        if (!args.text || typeof args.text !== 'string') return { error: 'text is required' }
        const text = (args.text as string).replace(/'/g, "\\'")
        const selector = args.selector as string | undefined
        if (selector) {
          await wc.executeJavaScript(`
            const el = document.querySelector('${cssEscape(selector)}')
            if (el) { el.focus(); el.value = '${text}'; el.dispatchEvent(new Event('input', { bubbles: true })) }
          `)
        } else {
          await wc.executeJavaScript(`
            const el = document.activeElement
            if (el && (el.tagName === 'INPUT' || el.tagName === 'TEXTAREA' || el.isContentEditable)) {
              if (el.isContentEditable) { el.textContent += '${text}' }
              else { el.value += '${text}'; el.dispatchEvent(new Event('input', { bubbles: true })) }
            }
          `)
        }
        return { success: true }
      }

      case 'scroll_page': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        const amount = (args.amount as number) || 300
        const scrollMap: Record<string, string> = {
          up: `window.scrollBy(0, -${amount})`,
          down: `window.scrollBy(0, ${amount})`,
          left: `window.scrollBy(-${amount}, 0)`,
          right: `window.scrollBy(${amount}, 0)`,
        }
        await wc.executeJavaScript(scrollMap[args.direction as string] ?? '')
        return { success: true }
      }

      case 'get_page_content': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        try {
          const content = await wc.executeJavaScript('document.body.innerText')
          return { content }
        } catch (err) {
          return { error: `Failed to get page content: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      case 'get_dom': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        const selector = args.selector as string
        if (!selector) return { error: 'selector is required' }
        try {
          const html = await wc.executeJavaScript(`
            (function() {
              const el = document.querySelector('${cssEscape(selector)}');
              if (!el) return null;

              const clone = el.cloneNode(true);

              // 移除 script / style / noscript
              clone.querySelectorAll('script, style, noscript, svg, path').forEach(n => n.remove());

              // 移除注释节点
              const walker = document.createTreeWalker(clone, NodeFilter.SHOW_COMMENT);
              const comments = [];
              while (walker.nextNode()) comments.push(walker.currentNode);
              comments.forEach(n => n.remove());

              // 收集关键属性白名单（按标签类型）
              const keepAttrs = {
                '*': ['id', 'class', 'role', 'aria-label', 'aria-expanded', 'aria-selected', 'aria-checked', 'aria-disabled', 'placeholder', 'type', 'name', 'value', 'href', 'src', 'alt', 'title', 'disabled', 'readonly', 'required', 'checked', 'selected'],
                'input': ['type', 'name', 'value', 'placeholder', 'disabled', 'readonly', 'required', 'checked'],
                'a': ['href', 'target'],
                'img': ['src', 'alt'],
                'form': ['action', 'method'],
                'option': ['value', 'selected'],
              };
              const globalSet = new Set(keepAttrs['*']);

              clone.querySelectorAll('*').forEach(node => {
                const tagAttrs = keepAttrs[node.tagName.toLowerCase()] || [];
                const allowed = new Set([...globalSet, ...tagAttrs]);
                [...node.attributes].forEach(attr => {
                  if (!allowed.has(attr.name)) node.removeAttribute(attr.name);
                });
              });

              let raw = clone.outerHTML;

              // 解码 HTML 实体
              const txt = document.createElement('textarea');

              // 多轮解码：&amp;quot; -> &quot; -> "
              for (let i = 0; i < 2; i++) {
                txt.innerHTML = raw;
                raw = txt.value;
              }

              // 压缩空白：多个空白字符变一个空格，去掉标签间空白
              raw = raw.replace(/\\s+/g, ' ');
              raw = raw.replace(/\\s*>/g, '>');
              raw = raw.replace(/<\\s*/g, '<');

              return raw;
            })()
          `)
          if (!html) return { error: `Element not found: ${selector}` }
          return { html }
        } catch (err) {
          return { error: `Failed to get DOM: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      case 'get_page_screenshot': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        try {
          const image = await wc.capturePage()
          if (image.isEmpty()) return { error: 'Page is empty or not loaded' }
          const jpeg = image.toJPEG(80)
          const size = image.getSize()

          // 保存到临时文件
          const filename = `screenshot-${Date.now()}.jpg`
          const screenshotDir = join(app.getPath('userData'), 'ai-screenshots')
          mkdirSync(screenshotDir, { recursive: true })
          writeFileSync(join(screenshotDir, filename), jpeg)

          const base64 = jpeg.toString('base64')
          return {
            _isImageContent: true,
            url: `screenshot://${filename}`,
            mediaType: 'image/jpeg',
            data: base64,
            width: size.width,
            height: size.height,
          }
        } catch (err) {
          return { error: `Screenshot failed: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      case 'select_option': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        if (!args.selector || typeof args.selector !== 'string') return { error: 'selector is required' }
        if (!args.value || typeof args.value !== 'string') return { error: 'value is required' }
        const selector = args.selector as string
        const value = (args.value as string).replace(/'/g, "\\'")
        await wc.executeJavaScript(`
          const el = document.querySelector('${cssEscape(selector)}')
          if (el) { el.value = '${value}'; el.dispatchEvent(new Event('change', { bubbles: true })) }
        `)
        return { success: true }
      }

      case 'hover_element': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        if (!args.selector || typeof args.selector !== 'string') return { error: 'selector is required' }
        const selector = args.selector as string
        await wc.executeJavaScript(`
          const el = document.querySelector('${cssEscape(selector)}')
          if (el) { el.dispatchEvent(new MouseEvent('mouseenter', { bubbles: true })); el.dispatchEvent(new MouseEvent('mouseover', { bubbles: true })) }
        `)
        return { success: true }
      }

      // ===== 页面感知工具 =====
      case 'get_page_summary': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        const pageCheck = checkPageAvailable(wc)
        if (pageCheck) return pageCheck
        try {
          return await extractPageSummary(wc)
        } catch (err) {
          return { error: `Failed to get page summary: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      case 'get_page_markdown': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        const pageCheck = checkPageAvailable(wc)
        if (pageCheck) return pageCheck
        try {
          const maxLength = (args.maxLength as number) || 10000
          return await extractPageMarkdown(wc, maxLength)
        } catch (err) {
          return { error: `Failed to get page markdown: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      case 'get_interactive_nodes': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        const pageCheck = checkPageAvailable(wc)
        if (pageCheck) return pageCheck
        try {
          const viewportOnly = args.viewportOnly !== false
          return await extractInteractiveNodes(wc, viewportOnly)
        } catch (err) {
          return { error: `Failed to get interactive nodes: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      case 'get_interactive_node_detail': {
        const wc = getWebContentsFromManager(args.tabId as string | undefined)
        if (!wc) return { error: 'Tab not found' }
        const pageCheck = checkPageAvailable(wc)
        if (pageCheck) return pageCheck
        try {
          const selector = args.selector as string
          if (!selector) return { error: 'selector is required' }
          return await extractInteractiveNodeDetail(wc, selector)
        } catch (err) {
          return { error: `Failed to get node detail: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      // ===== 技能管理工具 =====
      case 'write_skill': {
        const skillName = args.name as string
        const skillDesc = args.description as string
        const skillContent = args.content as string
        if (!skillName || !skillDesc || !skillContent) {
          return { error: 'name, description, content 均为必填' }
        }
        try {
          const skill = writeSkill(skillName, skillDesc, skillContent)
          return { success: true, name: skill.name, message: `Skill "${skill.name}" 已保存` }
        } catch (err) {
          return { error: `保存失败: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      case 'read_skill': {
        const skillName = args.name as string
        if (!skillName) return { error: 'name 为必填' }
        const skill = readSkill(skillName)
        if (!skill) return { error: `Skill "${skillName}" 不存在` }
        return { name: skill.name, description: skill.description, content: skill.content, updated: skill.updated }
      }

      case 'list_skills': {
        const skills = listSkills()
        return { skills, total: skills.length }
      }

      case 'search_skill': {
        const query = args.name as string
        if (!query) return { error: 'name (搜索关键词) 为必填' }
        const results = searchSkill(query)
        return { skills: results, total: results.length }
      }

      case 'inject_js': {
        const wcId = args.webContentId as number
        if (!wcId) return { error: 'webContentId is required' }
        if (!args.code || typeof args.code !== 'string') return { error: 'code is required' }
        try {
          const wc = webContents.fromId(wcId)
          if (!wc || wc.isDestroyed()) return { error: `WebContents not found or destroyed: ${wcId}` }
          const result = await wc.executeJavaScript(args.code as string)
          return { success: true, result }
        } catch (err) {
          return { error: `JS execution failed: ${err instanceof Error ? err.message : String(err)}` }
        }
      }

      default:
        console.warn(`[ai-proxy executeTool] unknown tool: ${name}`)
        return { error: `Unknown tool: ${name}` }
    }
  } catch (err) {
    console.error(`[ai-proxy executeTool] error executing ${name}:`, err)
    return { error: err instanceof Error ? err.message : String(err) }
  }
}

/** 检查页面是否可用于内容提取（内部页面、未加载完成） */
function checkPageAvailable(wc: Electron.WebContents): { error: string } | null {
  const url = wc.getURL()
  if (
    url.startsWith('sessionbox://') ||
    url === 'about:blank' ||
    url.startsWith('chrome-error://') ||
    url === ''
  ) {
    return { error: 'Cannot extract content from internal pages' }
  }
  if (wc.isLoading()) {
    return { error: 'Page is still loading' }
  }
  return null
}

/** 获取 webContents */
function getWebContentsFromManager(tabId?: string): Electron.WebContents | null {
  if (!tabId) {
    tabId = webviewManager.getActiveTabId() ?? undefined
  }
  if (!tabId) return null
  return webviewManager.getWebContents?.(tabId) ?? null
}

/** CSS 选择器转义 */
function cssEscape(selector: string): string {
  return selector.replace(/'/g, "\\'")
}


/**
 * 测试供应商连接是否正常
 */
export async function testProviderConnection(providerId: string): Promise<{ success: boolean; error?: string }> {
  const provider = getAIProvider(providerId)
  if (!provider) {
    return { success: false, error: `Provider not found: ${providerId}` }
  }

  try {
    const apiUrl = `${provider.apiBase.replace(/\/$/, '')}/v1/messages`
    const response = await fetch(apiUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': provider.apiKey,
        'anthropic-version': '2023-06-01',
        'anthropic-dangerous-direct-browser-access': 'true',
      },
      body: JSON.stringify({
        model: provider.models[0]?.id ?? 'claude-sonnet-4-6-20250514',
        messages: [{ role: 'user', content: 'Hi' }],
        max_tokens: 10,
        stream: false,
      }),
    })

    if (response.ok) {
      return { success: true }
    }
    const errorText = await response.text()
    return { success: false, error: `HTTP ${response.status}: ${errorText}` }
  } catch (error) {
    return {
      success: false,
      error: error instanceof Error ? error.message : String(error),
    }
  }
}

import { BrowserWindow } from 'electron'
import { net } from 'electron'
import { randomUUID } from 'node:crypto'
import Queue from 'queue'

// ====== 类型定义 ======

export interface CheckConfig {
  bookmarks: Array<{ id: string; url: string; title?: string }>
  maxRetries: number
  concurrency: number
  useProxy: boolean
  timeout: number
}

interface CheckResult {
  taskId: string
  bookmarkId: string
  status: 'valid' | 'invalid'
  statusCode?: number
  error?: string
  retries: number
  title?: string
  url?: string
}

interface DoneEvent {
  taskId: string
  total: number
  valid: number
  invalid: number
}

// ====== 活跃任务管理 ======

const activeTasks = new Map<string, { abortController: AbortController; queue: Queue }>()

// ====== 核心逻辑 ======

/**
 * 检查单个 URL 可达性
 * - HEAD 请求优先，失败降级 GET
 * - 2xx/3xx/4xx 视为有效（URL 可达）
 * - 超时/网络错误/DNS 失败 → 失效
 */
async function checkUrl(
  url: string,
  timeout: number,
  signal: AbortSignal,
  maxRetries: number
): Promise<Pick<CheckResult, 'status' | 'statusCode' | 'error' | 'retries'>> {
  let lastError = ''

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    if (signal.aborted) {
      return { status: 'invalid', error: '已取消', retries: attempt }
    }

    try {
      const controller = new AbortController()
      const timeoutId = setTimeout(() => controller.abort(), timeout)

      // 监听外部取消信号
      const onExternalAbort = (): void => controller.abort()
      signal.addEventListener('abort', onExternalAbort, { once: true })

      try {
        // 先尝试 HEAD
        let response: Electron.FetchResponse
        try {
          response = await net.fetch(url, {
            method: 'HEAD',
            signal: controller.signal,
            redirect: 'follow'
          })
        } catch {
          // HEAD 失败，降级 GET（某些服务器不支持 HEAD）
          if (signal.aborted) throw new Error('已取消')
          response = await net.fetch(url, {
            method: 'GET',
            signal: controller.signal,
            redirect: 'follow'
          })
        }

        const code = response.status

        if (code >= 200 && code < 500) {
          // 2xx/3xx → 有效，4xx → 有效（服务端可达，只是拒绝访问）
          return {
            status: 'valid',
            statusCode: code,
            retries: attempt
          }
        }

        // 5xx → 服务端错误，视为失效
        lastError = `HTTP ${code}`
      } finally {
        signal.removeEventListener('abort', onExternalAbort)
        clearTimeout(timeoutId)
      }
    } catch (err) {
      if (signal.aborted) {
        return { status: 'invalid', error: '已取消', retries: attempt }
      }
      lastError = err instanceof Error ? err.message : String(err)
    }

    // 重试前等待 1s（最后一次不等待）
    if (attempt < maxRetries) {
      await new Promise<void>((resolve) => {
        const timer = setTimeout(resolve, 1000)
        signal.addEventListener('abort', () => {
          clearTimeout(timer)
          resolve()
        }, { once: true })
      })
    }
  }

  return { status: 'invalid', error: lastError, retries: maxRetries }
}

/**
 * 启动书签健康检查任务
 */
export function startCheck(sender: Electron.WebContents, config: CheckConfig): string {
  const taskId = randomUUID()
  const abortController = new AbortController()

  const q = new Queue({ concurrency: config.concurrency, autostart: false })

  let valid = 0
  let invalid = 0
  let completed = 0
  const total = config.bookmarks.length

  for (const bookmark of config.bookmarks) {
    q.push(async (): Promise<void> => {
      if (abortController.signal.aborted) return

      const result = await checkUrl(
        bookmark.url,
        config.timeout,
        abortController.signal,
        config.maxRetries
      )

      if (abortController.signal.aborted) return

      if (result.status === 'valid') {
        valid++
      } else {
        invalid++
      }
      completed++

      const progressEvent: CheckResult = {
        taskId,
        bookmarkId: bookmark.id,
        title: bookmark.title,
        url: bookmark.url,
        ...result
      }

      try {
        sender.send('on:bookmark-check:progress', progressEvent)
      } catch {
        // 窗口可能已关闭
      }
    })
  }

  q.addEventListener('end', () => {
    activeTasks.delete(taskId)

    const doneEvent: DoneEvent = { taskId, total, valid, invalid }
    try {
      sender.send('on:bookmark-check:done', doneEvent)
    } catch {
      // 窗口可能已关闭
    }
  })

  q.addEventListener('error', (event: any) => {
    console.error('[BookmarkChecker] queue error:', event.detail ?? event)
  })

  activeTasks.set(taskId, { abortController, queue: q })
  q.start()

  return taskId
}

/**
 * 取消检查任务
 */
export function cancelCheck(taskId: string): void {
  const task = activeTasks.get(taskId)
  if (!task) return

  task.abortController.abort()
  task.queue.stop()
  activeTasks.delete(taskId)
}

import { join } from 'path'
import { app } from 'electron'
import { randomUUID } from 'crypto'
import { JsonStore } from '../utils/json-store'
import { pluginEventBus } from './plugin-event-bus'
import type { Bookmark, BookmarkFolder } from './store'

interface BookmarkStoreData {
  bookmarks: Bookmark[]
  bookmarkFolders: BookmarkFolder[]
}

const defaults: BookmarkStoreData = {
  bookmarks: [],
  bookmarkFolders: [],
}

export const bookmarkStore = new JsonStore<BookmarkStoreData>(
  join(app.getPath('userData'), 'bookmark-store.json'),
  defaults
)

// ====== 书签操作 ======

export function listBookmarks(folderId?: string): Bookmark[] {
  const sites = bookmarkStore.get('bookmarks') ?? defaults.bookmarks
  const sorted = [...sites].sort((a, b) => a.order - b.order)
  if (folderId) return sorted.filter((s) => s.folderId === folderId)
  return sorted
}

export function createBookmark(data: Omit<Bookmark, 'id'>): Bookmark {
  const sites = bookmarkStore.get('bookmarks') ?? []
  const site: Bookmark = { ...data, id: randomUUID() }
  sites.push(site)
  bookmarkStore.set('bookmarks', sites)
  try { pluginEventBus.emit('bookmark:created', site) } catch {}
  return site
}

export function updateBookmark(id: string, data: Partial<Omit<Bookmark, 'id'>>): void {
  const sites = bookmarkStore.get('bookmarks') ?? []
  const idx = sites.findIndex((s) => s.id === id)
  if (idx === -1) throw new Error(`书签 ${id} 不存在`)
  sites[idx] = { ...sites[idx], ...data }
  bookmarkStore.set('bookmarks', sites)
  try { pluginEventBus.emit('bookmark:updated', { id, ...data }) } catch {}
}

export function deleteBookmark(id: string): void {
  const sites = (bookmarkStore.get('bookmarks') ?? []).filter((s) => s.id !== id)
  bookmarkStore.set('bookmarks', sites)
  try { pluginEventBus.emit('bookmark:deleted', id) } catch {}
}

export function batchDeleteBookmarks(ids: string[]): void {
  const idSet = new Set(ids)
  const sites = (bookmarkStore.get('bookmarks') ?? []).filter((s) => !idSet.has(s.id))
  bookmarkStore.set('bookmarks', sites)
  try { pluginEventBus.emit('bookmark:batch-deleted', ids) } catch {}
}

export function reorderBookmarks(ids: string[]): void {
  const sites = bookmarkStore.get('bookmarks') ?? []
  ids.forEach((id, order) => {
    const s = sites.find((s) => s.id === id)
    if (s) s.order = order
  })
  bookmarkStore.set('bookmarks', sites)
}

export function batchCreateBookmarks(items: Omit<Bookmark, 'id'>[]): Bookmark[] {
  const sites = bookmarkStore.get('bookmarks') ?? []
  const created: Bookmark[] = []
  for (const data of items) {
    const bookmark: Bookmark = { ...data, id: randomUUID() }
    sites.push(bookmark)
    created.push(bookmark)
  }
  bookmarkStore.set('bookmarks', sites)
  return created
}

// ====== 书签文件夹操作 ======

export function listBookmarkFolders(): BookmarkFolder[] {
  const folders = bookmarkStore.get('bookmarkFolders') ?? defaults.bookmarkFolders
  return [...folders].sort((a, b) => a.order - b.order)
}

export function createBookmarkFolder(data: Omit<BookmarkFolder, 'id'>): BookmarkFolder {
  const folders = bookmarkStore.get('bookmarkFolders') ?? []
  const folder: BookmarkFolder = { ...data, id: randomUUID() }
  folders.push(folder)
  bookmarkStore.set('bookmarkFolders', folders)
  try { pluginEventBus.emit('bookmark-folder:created', folder) } catch {}
  return folder
}

export function updateBookmarkFolder(id: string, data: Partial<Omit<BookmarkFolder, 'id'>>): void {
  const folders = bookmarkStore.get('bookmarkFolders') ?? []
  const idx = folders.findIndex((f) => f.id === id)
  if (idx === -1) throw new Error(`文件夹 ${id} 不存在`)
  folders[idx] = { ...folders[idx], ...data }
  bookmarkStore.set('bookmarkFolders', folders)
  try { pluginEventBus.emit('bookmark-folder:updated', { id, ...data }) } catch {}
}

export function deleteBookmarkFolder(id: string): void {
  const folders = bookmarkStore.get('bookmarkFolders') ?? []
  const childIds = collectChildFolderIds(folders, id)
  const idsToDelete = [id, ...childIds]
  bookmarkStore.set('bookmarkFolders', folders.filter((f) => !idsToDelete.includes(f.id)))
  const sites = (bookmarkStore.get('bookmarks') ?? []).filter((s) => !idsToDelete.includes(s.folderId))
  bookmarkStore.set('bookmarks', sites)
  try { pluginEventBus.emit('bookmark-folder:deleted', id) } catch {}
}

export function deleteEmptyBookmarkFolders(): string[] {
  const folders = bookmarkStore.get('bookmarkFolders') ?? []
  const bookmarks = bookmarkStore.get('bookmarks') ?? []

  const emptyIds = new Set<string>()
  for (const folder of folders) {
    const hasChildFolders = folders.some((f) => f.parentId === folder.id && !emptyIds.has(f.id))
    const hasBookmarks = bookmarks.some((b) => b.folderId === folder.id)
    if (!hasChildFolders && !hasBookmarks) {
      emptyIds.add(folder.id)
    }
  }

  if (emptyIds.size === 0) return []

  let changed = true
  while (changed) {
    changed = false
    for (const folder of folders) {
      if (emptyIds.has(folder.id)) continue
      const hasChildFolders = folders.some((f) => f.parentId === folder.id && !emptyIds.has(f.id))
      const hasBookmarks = bookmarks.some((b) => b.folderId === folder.id)
      if (!hasChildFolders && !hasBookmarks) {
        emptyIds.add(folder.id)
        changed = true
      }
    }
  }

  bookmarkStore.set(
    'bookmarkFolders',
    folders.filter((f) => !emptyIds.has(f.id))
  )
  return [...emptyIds]
}

export function reorderBookmarkFolders(ids: string[]): void {
  const folders = bookmarkStore.get('bookmarkFolders') ?? []
  ids.forEach((id, order) => {
    const f = folders.find((f) => f.id === id)
    if (f) f.order = order
  })
  bookmarkStore.set('bookmarkFolders', folders)
}

export function batchCreateBookmarkFolders(items: Omit<BookmarkFolder, 'id'>[]): BookmarkFolder[] {
  const folders = bookmarkStore.get('bookmarkFolders') ?? []
  const created: BookmarkFolder[] = []
  for (const data of items) {
    const folder: BookmarkFolder = { ...data, id: randomUUID() }
    folders.push(folder)
    created.push(folder)
  }
  bookmarkStore.set('bookmarkFolders', folders)
  return created
}

function collectChildFolderIds(folders: BookmarkFolder[], parentId: string): string[] {
  const children = folders.filter((f) => f.parentId === parentId)
  const ids: string[] = []
  for (const child of children) {
    ids.push(child.id)
    ids.push(...collectChildFolderIds(folders, child.id))
  }
  return ids
}

import { BrowserWindow } from 'electron'
import { createServer, IncomingMessage, ServerResponse, Server } from 'node:http'
import { randomUUID } from 'node:crypto'
import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js'
import { SSEServerTransport } from '@modelcontextprotocol/sdk/server/sse.js'
import * as store from '../store'
import * as bookmarkStore from '../bookmark-store'
import { webviewManager } from '../webview-manager'
import { registerAllTools } from './tools'
import type { ToolContext, McpStatus } from './types'

const DEFAULT_PORT = 9527

interface Session {
  server: McpServer
  transport: SSEServerTransport
}

class McpServerService {
  private httpServer: Server | null = null
  private sessions = new Map<string, Session>()
  private running = false
  private port = DEFAULT_PORT
  private toolCount = 0

  async start(): Promise<void> {
    if (this.running) return

    const ctx: ToolContext = {
      store,
      bookmarkStore,
      webviewManager,
      mainWindow: webviewManager.getMainWindow()
    }

    this.httpServer = createServer()

    // SSE 端点：客户端通过 GET /sse 建立 SSE 流
    this.httpServer.on('request', async (req: IncomingMessage, res: ServerResponse) => {
      const url = new URL(req.url || '/', `http://localhost:${this.port}`)
      const pathname = url.pathname

      // CORS
      res.setHeader('Access-Control-Allow-Origin', '*')
      res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, OPTIONS')
      res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization')

      if (req.method === 'OPTIONS') {
        res.writeHead(204)
        res.end()
        return
      }

      // GET /sse — 建立 SSE 连接
      if (req.method === 'GET' && pathname === '/sse') {
        try {
          const transport = new SSEServerTransport('/messages', res)
          const server = new McpServer({ name: 'sessionbox-mcp', version: '1.0.0' })
          this.toolCount = registerAllTools(server, ctx)
          await server.connect(transport)

          const sessionId = transport.sessionId
          this.sessions.set(sessionId, { server, transport })

          transport.onclose = () => {
            console.log(`[MCP] Session closed: ${sessionId}`)
            this.sessions.delete(sessionId)
          }

          console.log(`[MCP] New session: ${sessionId}, total: ${this.sessions.size}`)
        } catch (error) {
          console.error('[MCP] Error establishing SSE connection:', error)
          if (!res.headersSent) {
            res.writeHead(500)
            res.end('Internal server error')
          }
        }
        return
      }

      // POST /messages — 接收客户端消息
      if (req.method === 'POST' && pathname === '/messages') {
        const sessionId = url.searchParams.get('sessionId')
        if (!sessionId) {
          res.writeHead(400, { 'Content-Type': 'application/json' })
          res.end(JSON.stringify({ error: 'Missing sessionId' }))
          return
        }

        const session = this.sessions.get(sessionId)
        if (!session) {
          res.writeHead(404, { 'Content-Type': 'application/json' })
          res.end(JSON.stringify({ error: 'Session not found' }))
          return
        }

        try {
          const body = await this.parseBody(req)
          await session.transport.handlePostMessage(req, res, body)
        } catch (error) {
          console.error('[MCP] Error handling POST:', error)
          if (!res.headersSent) {
            res.writeHead(500, { 'Content-Type': 'application/json' })
            res.end(JSON.stringify({ error: 'Internal server error' }))
          }
        }
        return
      }

      // 未知路径
      res.writeHead(404)
      res.end('Not found')
    })

    await new Promise<void>((resolve, reject) => {
      this.httpServer!.listen(this.port, () => resolve())
      this.httpServer!.on('error', reject)
    })

    this.running = true
    console.log(`[MCP] Server started on port ${this.port}, ${this.toolCount} tools registered`)
  }

  async stop(): Promise<void> {
    if (!this.running) return

    try {
      // 关闭所有会话
      for (const [id, session] of this.sessions) {
        try {
          await session.transport.close()
          await session.server.close()
        } catch { /* ignore */ }
      }
      this.sessions.clear()

      if (this.httpServer) {
        await new Promise<void>((resolve) => {
          this.httpServer!.close(() => resolve())
        })
        this.httpServer = null
      }
    } catch (error) {
      console.error('[MCP] Error stopping server:', error)
    }

    this.running = false
    this.toolCount = 0
    console.log('[MCP] Server stopped')
  }

  getStatus(): McpStatus {
    return {
      enabled: store.getMcpEnabled(),
      running: this.running,
      toolCount: this.toolCount,
      port: this.port
    }
  }

  isRunning(): boolean {
    return this.running
  }

  getPort(): number {
    return this.port
  }

  private parseBody(req: IncomingMessage): Promise<unknown> {
    return new Promise((resolve, reject) => {
      const chunks: Buffer[] = []
      req.on('data', (chunk) => chunks.push(chunk))
      req.on('end', () => {
        const raw = Buffer.concat(chunks).toString('utf-8')
        if (!raw) {
          resolve(undefined)
          return
        }
        try {
          resolve(JSON.parse(raw))
        } catch {
          resolve(raw)
        }
      })
      req.on('error', reject)
    })
  }
}

export const mcpServerService = new McpServerService()

import { z } from 'zod'
import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js'
import type { ToolContext } from '../types'

/** 跟踪已 attach debugger 的 tab */
const attachedTabs = new Set<string>()

/** 当 tab 被销毁时清理 debugger 状态 */
export function cleanupDetachedTab(tabId: string): void {
  attachedTabs.delete(tabId)
}

/** 确保 debugger 已 attach 到目标 tab 的 WebContents */
function ensureDebuggerAttached(ctx: ToolContext, tabId: string): any {
  const wc = ctx.webviewManager.getWebContents(tabId)
  if (!wc) throw new Error(`No WebContents for tab ${tabId}`)

  if (!attachedTabs.has(tabId)) {
    wc.debugger.attach('1.3')
    attachedTabs.add(tabId)

    // 启用常用域
    try { wc.debugger.sendCommand('Runtime.enable') } catch {}
    try { wc.debugger.sendCommand('Page.enable') } catch {}
    try { wc.debugger.sendCommand('Network.enable') } catch {}
  }

  return wc
}

/** 成功响应 */
function ok(data: Record<string, unknown>) {
  return {
    content: [{ type: 'text' as const, text: JSON.stringify({ success: true, ...data }, null, 2) }]
  }
}

/** 错误响应 */
function err(message: string) {
  return {
    content: [{ type: 'text' as const, text: JSON.stringify({ success: false, error: message }, null, 2) }]
  }
}

export function registerCdpTools(server: McpServer, ctx: ToolContext): number {
  // 1. execute_js
  server.tool(
    'execute_js',
    'Execute JavaScript code in a tab and return the result',
    {
      tabId: z.string().describe('Tab ID to execute JavaScript in'),
      code: z.string().describe('JavaScript code to execute')
    },
    async ({ tabId, code }) => {
      try {
        const wc = ctx.webviewManager.getWebContents(tabId)
        if (!wc) return err(`No WebContents for tab ${tabId}`)

        // 10 秒超时保护
        const result = await Promise.race([
          wc.executeJavaScript(code),
          new Promise<never>((_, reject) =>
            setTimeout(() => reject(new Error('Execution timed out after 10s')), 10_000)
          )
        ])

        return ok({ tabId, result: result ?? null })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 2. cdp_command
  server.tool(
    'cdp_command',
    'Send a Chrome DevTools Protocol command to a tab',
    {
      tabId: z.string().describe('Tab ID to send CDP command to'),
      method: z.string().describe('CDP method name (e.g. "Runtime.evaluate", "Page.captureScreenshot")'),
      // Zod 4's JSON Schema conversion crashes on single-argument z.record(valueSchema)
      params: z.record(z.string(), z.any()).optional().describe('CDP command parameters')
    },
    async ({ tabId, method, params }) => {
      try {
        const wc = ensureDebuggerAttached(ctx, tabId)
        const result = await wc.debugger.sendCommand(method, params ?? {})
        return ok({ tabId, method, result })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 3. screenshot
  server.tool(
    'screenshot',
    'Capture a screenshot of a tab and return the base64 image data',
    {
      tabId: z.string().describe('Tab ID to screenshot')
    },
    async ({ tabId }) => {
      try {
        const dataUrl = await ctx.webviewManager.captureTab(tabId)
        if (!dataUrl) return err(`Failed to capture tab ${tabId} (tab may be frozen or not loaded)`)

        // 提取 base64 部分: "data:image/png;base64,XXXXX"
        const base64 = dataUrl.replace(/^data:image\/[^;]+;base64,/, '')

        return ok({
          tabId,
          format: 'png',
          sizeBytes: Buffer.from(base64, 'base64').length,
          data: base64
        })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  return 3
}

import { z } from 'zod'
import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js'
import type { ToolContext } from '../types'

/** 统一文本返回格式 */
function text(data: unknown) {
  return {
    content: [{ type: 'text' as const, text: JSON.stringify(data, null, 2) }]
  }
}

export function registerQueryTools(server: McpServer, ctx: ToolContext): number {
  // 1. list_workspaces
  server.tool(
    'list_workspaces',
    'List all workspaces in SessionBox',
    async () => {
      const workspaces = ctx.store.listWorkspaces()
      return text(workspaces)
    }
  )

  // 2. list_groups
  server.tool(
    'list_groups',
    'List all groups across workspaces',
    async () => {
      const groups = ctx.store.listGroups()
      return text(groups)
    }
  )

  // 3. list_containers
  server.tool(
    'list_containers',
    'List all containers (session isolation units)',
    async () => {
      const containers = ctx.store.listContainers()
      return text(containers)
    }
  )

  // 4. list_pages
  server.tool(
    'list_pages',
    'List all pages (bound to groups and containers)',
    async () => {
      const pages = ctx.store.listPages()
      return text(pages)
    }
  )

  // 5. list_tabs (聚合运行时信息)
  server.tool(
    'list_tabs',
    'List all tabs with runtime info (active state, frozen state, current URL)',
    async () => {
      console.log('[MCP list_tabs] called')

      const tabs = ctx.store.listTabs()
      console.log('[MCP list_tabs] store.listTabs() count:', tabs.length)
      if (tabs.length > 0) {
        console.log('[MCP list_tabs] first tab:', JSON.stringify(tabs[0]))
      }

      const activeTabId = ctx.webviewManager.getActiveTabId()
      console.log('[MCP list_tabs] activeTabId:', activeTabId)

      // 检查 webviewManager 中实际管理的视图
      const managedViewCount = ctx.webviewManager.getManagedViewCount?.() ?? 'N/A'
      console.log('[MCP list_tabs] webviewManager managed views:', managedViewCount)

      const result = tabs.map((tab) => {
        const viewInfo = ctx.webviewManager.getViewInfo(tab.id)
        const page = tab.pageId ? ctx.store.getPageById(tab.pageId) : undefined
        const group = page?.groupId ? ctx.store.getGroupById(page.groupId) : undefined
        const workspace = group?.workspaceId
          ? ctx.store.listWorkspaces().find((w) => w.id === group.workspaceId)
          : undefined

        return {
          tabId: tab.id,
          pageId: tab.pageId,
          title: tab.title,
          url: viewInfo?.url ?? tab.url,
          isActive: tab.id === activeTabId,
          isFrozen: ctx.webviewManager.isFrozen(tab.id),
          containerId: viewInfo?.containerId ?? page?.containerId,
          groupName: group?.name,
          workspaceName: workspace?.title,
          pinned: tab.pinned,
          muted: tab.muted
        }
      })

      console.log('[MCP list_tabs] returning', result.length, 'tabs')
      return text(result)
    }
  )

  // 6. list_bookmarks
  server.tool(
    'list_bookmarks',
    'List all bookmarks',
    async () => {
      const bookmarks = ctx.bookmarkStore.listBookmarks()
      return text(bookmarks)
    }
  )

  // 7. list_proxies
  server.tool(
    'list_proxies',
    'List all proxy configurations',
    async () => {
      const proxies = ctx.store.listProxies()
      return text(proxies)
    }
  )

  // 8. get_tab_detail (深度关联查询)
  server.tool(
    'get_tab_detail',
    'Get detailed information for a specific tab, including page, group, workspace, container, and proxy info',
    {
      tabId: z.string().describe('The tab ID to query')
    },
    async ({ tabId }) => {
      const tabs = ctx.store.listTabs()
      const tab = tabs.find((t) => t.id === tabId)
      if (!tab) {
        return text({ error: `Tab ${tabId} not found` })
      }

      // 通过 pageId 查询关联数据
      const page = tab.pageId ? ctx.store.getPageById(tab.pageId) : undefined
      const group = page?.groupId ? ctx.store.getGroupById(page.groupId) : undefined
      const workspace = group?.workspaceId
        ? ctx.store.listWorkspaces().find((w) => w.id === group.workspaceId)
        : undefined
      const container = page?.containerId
        ? ctx.store.getContainerById(page.containerId)
        : undefined

      // 查询代理：页面级 > 容器级 > 分组级
      const proxyId = page?.proxyId ?? container?.proxyId ?? group?.proxyId
      const proxy = proxyId ? ctx.store.getProxyById(proxyId) : undefined

      // 运行时信息
      const viewInfo = ctx.webviewManager.getViewInfo(tabId)
      const activeTabId = ctx.webviewManager.getActiveTabId()

      const detail = {
        tab: {
          id: tab.id,
          pageId: tab.pageId,
          title: tab.title,
          url: viewInfo?.url ?? tab.url,
          order: tab.order,
          pinned: tab.pinned,
          muted: tab.muted,
          isActive: tab.id === activeTabId,
          isFrozen: ctx.webviewManager.isFrozen(tabId)
        },
        page: page
          ? { id: page.id, name: page.name, icon: page.icon, url: page.url, userAgent: page.userAgent }
          : null,
        group: group ? { id: group.id, name: group.name, color: group.color } : null,
        workspace: workspace
          ? { id: workspace.id, title: workspace.title, color: workspace.color }
          : null,
        container: container
          ? { id: container.id, name: container.name, icon: container.icon }
          : null,
        proxy: proxy
          ? {
              id: proxy.id,
              name: proxy.name,
              type: proxy.type,
              host: proxy.host,
              port: proxy.port,
              enabled: proxy.enabled
            }
          : null
      }

      return text(detail)
    }
  )

  return 8
}

