export function registerTabTools(server: McpServer, ctx: ToolContext): number {
  // 1. create_tab
  server.tool(
    'create_tab',
    'Create a new tab. Provide pageId to open from an existing page, or url to open a direct URL.',
    {
      pageId: z.string().optional().describe('Existing page ID to create tab from'),
      url: z.string().optional().describe('URL to open (used when no pageId)'),
      containerId: z.string().optional().describe('Container ID (required when using url without pageId)')
    },
    async ({ pageId, url, containerId }) => {
      try {
        let finalPageId = pageId ?? ''
        let finalUrl = url ?? ''
        let finalContainerId = containerId ?? ''

        if (pageId) {
          // 通过页面创建
          const page = ctx.store.getPageById(pageId)
          if (!page) return err(`Page ${pageId} not found`)
          finalUrl = page.url
          finalContainerId = page.containerId ?? 'default'
        } else if (url) {
          // 通过 URL 创建，使用默认容器
          finalContainerId = finalContainerId || ctx.store.getDefaultContainerId()
        } else {
          return err('Must provide either pageId or url')
        }

        // 计算 order
        const existingTabs = ctx.store.listTabs()
        const maxOrder = existingTabs.length > 0
          ? Math.max(...existingTabs.map((t) => t.order))
          : -1

        // 创建 tab 数据
        const tab = ctx.store.createTab({
          pageId: finalPageId,
          title: '',
          url: finalUrl,
          order: maxOrder + 1
        })

        // 注册视图
        ctx.webviewManager.registerPendingView(tab.id, finalPageId, finalContainerId, finalUrl)

        // 通知渲染进程
        ctx.mainWindow?.webContents.send('on:tab:created', tab)

        return ok({ tabId: tab.id, url: finalUrl })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 2. navigate_tab
  server.tool(
    'navigate_tab',
    'Navigate a tab to a new URL',
    {
      tabId: z.string().describe('Tab ID to navigate'),
      url: z.string().describe('URL to navigate to')
    },
    async ({ tabId, url }) => {
      try {
        ctx.webviewManager.navigate(tabId, url)
        return ok({ tabId, url })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 3. close_tab
  server.tool(
    'close_tab',
    'Close (destroy) a tab',
    {
      tabId: z.string().describe('Tab ID to close')
    },
    async ({ tabId }) => {
      try {
        ctx.webviewManager.destroyView(tabId)
        ctx.store.deleteTab(tabId)
        return ok({ tabId, closed: true })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 4. switch_tab
  server.tool(
    'switch_tab',
    'Switch to (activate) a tab',
    {
      tabId: z.string().describe('Tab ID to switch to')
    },
    async ({ tabId }) => {
      try {
        ctx.webviewManager.switchView(tabId)
        return ok({ tabId, activated: true })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 5. reload_tab
  server.tool(
    'reload_tab',
    'Reload the current page in a tab',
    {
      tabId: z.string().describe('Tab ID to reload'),
      ignoreCache: z.boolean().optional().describe('Whether to bypass cache (hard reload)')
    },
    async ({ tabId, ignoreCache }) => {
      try {
        if (ignoreCache) {
          ctx.webviewManager.forceReload(tabId)
        } else {
          ctx.webviewManager.reload(tabId)
        }
        return ok({ tabId, reloaded: true, ignoreCache: !!ignoreCache })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 6. go_back
  server.tool(
    'go_back',
    'Navigate back in a tab',
    {
      tabId: z.string().describe('Tab ID to go back in')
    },
    async ({ tabId }) => {
      try {
        ctx.webviewManager.goBack(tabId)
        return ok({ tabId, action: 'go_back' })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 7. go_forward
  server.tool(
    'go_forward',
    'Navigate forward in a tab',
    {
      tabId: z.string().describe('Tab ID to go forward in')
    },
    async ({ tabId }) => {
      try {
        ctx.webviewManager.goForward(tabId)
        return ok({ tabId, action: 'go_forward' })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  return 7
}

import { BrowserWindow } from 'electron'
import { z } from 'zod'
import { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js'
import type { ToolContext } from '../types'

/** 成功响应 */
function ok(data: Record<string, unknown>) {
  return {
    content: [{ type: 'text' as const, text: JSON.stringify({ success: true, ...data }, null, 2) }]
  }
}

/** 错误响应 */
function err(message: string) {
  return {
    content: [{ type: 'text' as const, text: JSON.stringify({ success: false, error: message }, null, 2) }]
  }
}

/** 根据 ID 查找窗口，找不到返回 null */
function findWindow(windowId: number): BrowserWindow | null {
  const win = BrowserWindow.getAllWindows().find(w => w.id === windowId)
  if (!win || win.isDestroyed()) return null
  return win
}

export function registerWindowTools(server: McpServer, ctx: ToolContext): number {
  // 1. create_window
  server.tool(
    'create_window',
    'Create an independent BrowserWindow',
    {
      url: z.string().describe('URL to open'),
      containerId: z.string().optional().describe('Container ID for session isolation'),
      title: z.string().optional().describe('Window title'),
      width: z.number().optional().describe('Window width (default 1280)'),
      height: z.number().optional().describe('Window height (default 800)')
    },
    async ({ url, containerId, title, width, height }) => {
      try {
        const partition = containerId
          ? `persist:container-${containerId}`
          : undefined

        const win = new BrowserWindow({
          width: width ?? 1280,
          height: height ?? 800,
          show: false,
          autoHideMenuBar: true,
          title: title ?? '新窗口',
          webPreferences: {
            partition,
            sandbox: false
          }
        })
        win.loadURL(url)
        win.once('ready-to-show', () => win.show())

        return ok({ windowId: win.id, title: title ?? '新窗口', url, containerId })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 2. navigate_window
  server.tool(
    'navigate_window',
    'Navigate a window to a new URL',
    {
      windowId: z.number().describe('Window ID to navigate'),
      url: z.string().describe('URL to navigate to')
    },
    async ({ windowId, url }) => {
      try {
        const win = findWindow(windowId)
        if (!win) return err(`Window ${windowId} not found or destroyed`)
        void win.webContents.loadURL(url)
        return ok({ windowId, url })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 3. close_window
  server.tool(
    'close_window',
    'Close a window',
    {
      windowId: z.number().describe('Window ID to close')
    },
    async ({ windowId }) => {
      try {
        const win = findWindow(windowId)
        if (!win) return err(`Window ${windowId} not found or destroyed`)
        win.close()
        return ok({ windowId, closed: true })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 4. list_windows
  server.tool(
    'list_windows',
    'List all open windows',
    {},
    async () => {
      try {
        const windows = BrowserWindow.getAllWindows().map(w => ({
          windowId: w.id,
          title: w.getTitle(),
          url: w.webContents.getURL(),
          width: w.getBounds().width,
          height: w.getBounds().height,
          isMaximized: w.isMaximized(),
          isMain: w === ctx.webviewManager?.getMainWindow?.()
        }))
        return ok({ windows })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 5. focus_window
  server.tool(
    'focus_window',
    'Focus (bring to front) a window',
    {
      windowId: z.number().describe('Window ID to focus')
    },
    async ({ windowId }) => {
      try {
        const win = findWindow(windowId)
        if (!win) return err(`Window ${windowId} not found or destroyed`)
        if (win.isMinimized()) win.restore()
        win.focus()
        return ok({ windowId, focused: true })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 6. screenshot_window
  server.tool(
    'screenshot_window',
    'Take a screenshot of a window',
    {
      windowId: z.number().describe('Window ID to screenshot')
    },
    async ({ windowId }) => {
      try {
        const win = findWindow(windowId)
        if (!win) return err(`Window ${windowId} not found or destroyed`)
        const image = await win.webContents.capturePage()
        if (image.isEmpty()) return err('Window content is empty')
        const base64 = image.toJPEG(80).toString('base64')
        return ok({ windowId, imageBase64: base64, width: image.getSize().width, height: image.getSize().height })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  // 7. get_window_detail
  server.tool(
    'get_window_detail',
    'Get detailed info about a window',
    {
      windowId: z.number().describe('Window ID')
    },
    async ({ windowId }) => {
      try {
        const win = findWindow(windowId)
        if (!win) return err(`Window ${windowId} not found or destroyed`)
        const bounds = win.getBounds()
        return ok({
          windowId: win.id,
          title: win.getTitle(),
          url: win.webContents.getURL(),
          bounds,
          isMaximized: win.isMaximized(),
          isMinimized: win.isMinimized(),
          isFullScreen: win.isFullScreen(),
          isFocused: win.isFocused(),
          isMain: win === ctx.webviewManager?.getMainWindow?.()
        })
      } catch (error: any) {
        return err(error?.message ?? String(error))
      }
    }
  )

  return 7
}

import { join } from 'path'
import { app } from 'electron'
import { existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync, unlinkSync } from 'node:fs'
import { randomUUID } from 'crypto'
import Store from 'electron-store'
import type { Bookmark, BookmarkFolder, PasswordEntry, Page, Workflow, WorkflowFolder } from './store'

const BOOKMARK_BAR_FOLDER_ID = '__bookmark_bar__'

const userDataPath = app.getPath('userData')

interface LegacyStoreSchema {
  bookmarks: Bookmark[]
  bookmarkFolders: BookmarkFolder[]
  passwords: PasswordEntry[]
  favoriteSites: any[]
  pages: Page[]
  workflows: Workflow[]
  workflowFolders: WorkflowFolder[]
  [key: string]: unknown
}

/** 迁移 Bookmark 的 containerId → pageId（在 electron-store 内执行） */
function migrateBookmarkContainerIdToPageId(store: Store<LegacyStoreSchema>): void {
  const bookmarks = store.get('bookmarks', []) as Record<string, any>[]
  const pages = store.get('pages', [])
  let updated = false

  const newBookmarks = bookmarks.map(b => {
    if (b.pageId) return b
    if (b.containerId) {
      const page = pages.find((p: Page) => p.containerId === b.containerId)
      updated = true
      return { ...b, pageId: page?.id ?? '' }
    }
    return b
  })

  if (updated) {
    store.set('bookmarks', newBookmarks as Bookmark[])
    console.log('[Migration] Updated bookmarks with pageId')
  }
}

/** 迁移旧 favoriteSites 键名，以及为无 folderId 的旧书签分配文件夹 */
function legacyMigrateBookmarks(store: Store<LegacyStoreSchema>): void {
  if (store.has('favoriteSites')) {
    const oldData = store.get('favoriteSites', [])
    if (oldData.length > 0 && !store.has('bookmarks')) {
      store.set('bookmarks', oldData)
    }
    store.delete('favoriteSites')
  }

  const sites = store.get('bookmarks', [])
  if (sites.length === 0) return

  const needsMigration = sites.some((s) => !('folderId' in s) || s.folderId === undefined)
  if (!needsMigration) return

  let folders = store.get('bookmarkFolders', [])
  if (folders.length === 0) {
    const defaultFolder: BookmarkFolder = { id: randomUUID(), name: '默认文件夹', parentId: null, order: 0 }
    folders.push(defaultFolder)
    store.set('bookmarkFolders', folders)
  }
  const barFolder = folders.find((f) => f.id === BOOKMARK_BAR_FOLDER_ID)
  if (barFolder) {
    barFolder.name = '默认文件夹'
    store.set('bookmarkFolders', folders)
  }
  const fallbackFolderId = folders[0].id

  const migrated = sites.map((s, index) => ({
    ...s,
    folderId: s.folderId || fallbackFolderId,
    order: s.order ?? index
  }))
  store.set('bookmarks', migrated)
}

/**
 * 将 electron-store 中的 bookmarks、bookmarkFolders、passwords 迁移到独立的 JsonStore 文件。
 * 幂等设计：目标文件已存在则跳过。
 */
export function migrateBookmarksAndPasswords(): void {
  const bookmarkPath = join(userDataPath, 'bookmark-store.json')
  const passwordPath = join(userDataPath, 'password-store.json')

  const store = new Store<LegacyStoreSchema>()

  // 先执行旧迁移逻辑（操作 electron-store 中的数据）
  if (!existsSync(bookmarkPath)) {
    migrateBookmarkContainerIdToPageId(store)
    legacyMigrateBookmarks(store)
  }

  // 迁移书签
  if (!existsSync(bookmarkPath)) {
    const bookmarks = store.get('bookmarks', [])
    const bookmarkFolders = store.get('bookmarkFolders', [])

    writeFileSync(bookmarkPath, JSON.stringify({ bookmarks, bookmarkFolders }, null, 2), 'utf-8')

    if (bookmarks.length > 0 || bookmarkFolders.length > 0) {
      console.log(`[Migration] Migrated ${bookmarks.length} bookmarks and ${bookmarkFolders.length} folders to bookmark-store.json`)
    } else {
      console.log('[Migration] Created empty bookmark-store.json')
    }

    // 迁移成功，移除旧数据
    store.delete('bookmarks')
    store.delete('bookmarkFolders')
    console.log('[Migration] Removed bookmarks/bookmarkFolders from electron-store')
  }

  // 迁移密码
  if (!existsSync(passwordPath)) {
    const passwords = store.get('passwords', [])

    writeFileSync(passwordPath, JSON.stringify({ passwords }, null, 2), 'utf-8')

    if (passwords.length > 0) {
      console.log(`[Migration] Migrated ${passwords.length} passwords to password-store.json`)
    } else {
      console.log('[Migration] Created empty password-store.json')
    }

    // 迁移成功，移除旧数据
    store.delete('passwords')
    console.log('[Migration] Removed passwords from electron-store')
  }
}

/**
 * 将工作流数据迁移到独立文件：
 * - 文件夹 → workflow-folders.json
 * - 工作流 → workflows/{id}.json（每个工作流独立文件）
 *
 * 支持从 electron-store 或旧的单文件 workflow-store.json 迁移。
 * 幂等设计：目标目录已存在文件则跳过。
 */
export function migrateWorkflows(): void {
  const workflowsDir = join(userDataPath, 'workflows')
  const foldersPath = join(userDataPath, 'workflow-folders.json')
  const oldSinglePath = join(userDataPath, 'workflow-store.json')

  // 已迁移过（文件夹文件存在），跳过
  if (existsSync(foldersPath)) return

  let workflows: Workflow[] = []
  let workflowFolders: WorkflowFolder[] = []
  let source = ''

  // 优先从旧的单文件 workflow-store.json 读取
  if (existsSync(oldSinglePath)) {
    try {
      const data = JSON.parse(readFileSync(oldSinglePath, 'utf-8'))
      workflows = data.workflows ?? []
      workflowFolders = data.workflowFolders ?? []
      source = 'workflow-store.json'
    } catch {
      // 文件损坏，继续尝试 electron-store
    }
  }

  // 如果没从单文件读到，从 electron-store 读取
  if (!source) {
    const store = new Store<LegacyStoreSchema>()
    if (store.has('workflows') || store.has('workflowFolders')) {
      workflows = store.get('workflows', [])
      workflowFolders = store.get('workflowFolders', [])
      source = 'electron-store'
    }
  }

  // 没有数据需要迁移，创建空文件夹索引文件即可
  if (!source) {
    writeFileSync(foldersPath, JSON.stringify({ workflowFolders: [] }, null, 2), 'utf-8')
    mkdirSync(workflowsDir, { recursive: true })
    console.log('[Migration] Created empty workflow storage')
    return
  }

  // 写入文件夹索引
  writeFileSync(foldersPath, JSON.stringify({ workflowFolders }, null, 2), 'utf-8')

  // 写入每个工作流独立文件
  mkdirSync(workflowsDir, { recursive: true })
  for (const w of workflows) {
    writeFileSync(join(workflowsDir, `${w.id}.json`), JSON.stringify(w, null, 2), 'utf-8')
  }

  console.log(`[Migration] Migrated ${workflows.length} workflows and ${workflowFolders.length} folders from ${source}`)

  // 清理旧数据
  if (source === 'electron-store') {
    const store = new Store<LegacyStoreSchema>()
    store.delete('workflows')
    store.delete('workflowFolders')
    console.log('[Migration] Removed workflows/workflowFolders from electron-store')
  } else if (source === 'workflow-store.json') {
    unlinkSync(oldSinglePath)
    console.log('[Migration] Removed old workflow-store.json')
  }
}

/**
 * 页面信息提取模块
 * 通过 WebContents.executeJavaScript 注入 JS 脚本提取页面信息。
 * 函数签名接受 WebContents（而非 tabId），由调用方负责 tabId → WebContents 的映射。
 */
import { readFileSync } from 'fs'
import { join } from 'path'
import { app } from 'electron'

// 缓存库代码字符串，避免每次调用都读磁盘
let _readabilityCode: string | null = null
let _turndownCode: string | null = null

function getReadabilityCode(): string {
  if (!_readabilityCode) {
    const filePath = join(app.getAppPath(), 'node_modules', '@mozilla', 'readability', 'Readability.js')
    _readabilityCode = readFileSync(filePath, 'utf-8')
  }
  return _readabilityCode
}

function getTurndownCode(): string {
  if (!_turndownCode) {
    const filePath = join(app.getAppPath(), 'node_modules', 'turndown', 'dist', 'turndown.js')
    _turndownCode = readFileSync(filePath, 'utf-8')
  }
  return _turndownCode
}

// ===== 类型定义 =====

export interface PageSummary {
  title: string
  url: string
  description: string
  headings: Array<{ level: number; text: string }>
  links: Array<{ text: string; href: string }>
  meta: {
    author?: string
    keywords?: string
    ogTitle?: string
    ogDescription?: string
  }
}

export interface PageMarkdown {
  title: string
  byline: string
  excerpt: string
  markdown: string
  contentLength: number
  truncated: boolean
}

/** 交互节点简要信息（get_interactive_nodes 返回） */
export interface InteractiveNodeSimple {
  name: string
  text: string
  selector: string
}

/** 交互节点详细信息（get_interactive_node_detail 返回） */
export interface InteractiveNodeDetail {
  tag: string
  role: string
  name: string
  text: string
  selector: string
  rect: { x: number; y: number; width: number; height: number }
  visible: boolean
  clickable: boolean
  attributes: Record<string, string>
  styles: {
    display: string
    visibility: string
    opacity: string
    cursor: string
  }
  value?: string
  href?: string
}

export interface InteractiveNodesResult {
  nodes: InteractiveNodeSimple[]
  viewport: { width: number; height: number; scrollX: number; scrollY: number }
}

// ===== 提取函数 =====

/**
 * 提取页面结构化摘要（标题、heading、链接、meta 信息）
 * links 数组最多返回 50 条
 */
export async function extractPageSummary(wc: Electron.WebContents): Promise<PageSummary> {
  const result = await wc.executeJavaScript(`(function() {
    const getMeta = (name) => {
      const el = document.querySelector('meta[name="' + name + '"]') ||
                 document.querySelector('meta[property="' + name + '"]');
      return el ? el.getAttribute('content') || '' : '';
    };

    const headings = Array.from(document.querySelectorAll('h1,h2,h3,h4,h5,h6')).map(h => ({
      level: parseInt(h.tagName[1]),
      text: (h.textContent || '').trim()
    }));

    const links = Array.from(document.querySelectorAll('a[href]')).slice(0, 50).map(a => ({
      text: (a.textContent || '').trim(),
      href: a.href
    }));

    return {
      title: document.title || '',
      url: location.href,
      description: getMeta('description'),
      headings,
      links,
      meta: {
        author: getMeta('author'),
        keywords: getMeta('keywords'),
        ogTitle: getMeta('og:title'),
        ogDescription: getMeta('og:description'),
      }
    };
  })()`)

  return result
}

/**
 * 提取页面正文并转为 Markdown
 * 使用 Readability + Turndown 在浏览器上下文中执行（利用页面 DOM，无需 jsdom）
 * 库代码从本地 node_modules 读取后注入，不依赖 CDN，无 CSP 问题
 * maxLength 默认 10000 字符，超出截断并标记 truncated
 */
export async function extractPageMarkdown(
  wc: Electron.WebContents,
  maxLength: number = 10000,
): Promise<PageMarkdown> {
  // 从本地 node_modules 读取库代码（带缓存）
  const readabilityCode = getReadabilityCode()
  const turndownCode = getTurndownCode()

  // 将库代码 + 提取逻辑一起注入到浏览器上下文
  const result = await wc.executeJavaScript(`(function() {
    ${readabilityCode}
    ${turndownCode}

    try {
      // document.cloneNode(true) 克隆整个文档供 Readability 使用
      // 注意：template 内容和某些动态元素可能不会被完整克隆
      const doc = document.cloneNode(true);
      const reader = new Readability(doc);
      const article = reader.parse();

      if (!article) {
        return { title: document.title, byline: '', excerpt: '', markdown: '', contentLength: 0, truncated: false, error: 'Unable to extract article content' };
      }

      const turndown = new TurndownService({
        headingStyle: 'atx',
        codeBlockStyle: 'fenced',
      });
      const md = turndown.turndown(article.content || '');

      return {
        title: article.title || '',
        byline: article.byline || '',
        excerpt: article.excerpt || '',
        markdown: md,
        contentLength: md.length,
        truncated: false,
      };
    } catch(e) {
      return { title: document.title, byline: '', excerpt: '', markdown: '', contentLength: 0, truncated: false, error: e.message };
    }
  })()`)

  // 处理截断
  if (result.markdown && result.markdown.length > maxLength) {
    result.markdown = result.markdown.slice(0, maxLength) + '\n\n[truncated]'
    result.truncated = true
  }

  return result
}

/**
 * 提取页面中可见的交互节点（简要信息：name, text, selector）
 * 筛选规则：button、a[href]、input、textarea、select、[role]、[tabindex]
 * 可见性过滤：display !== none、visibility !== hidden、opacity > 0、rect 合理
 * 不穿透 shadow DOM
 */
export async function extractInteractiveNodes(
  wc: Electron.WebContents,
  viewportOnly: boolean = true,
): Promise<InteractiveNodesResult> {
  const result = await wc.executeJavaScript(`(function() {
    const INTERACTIVE_TAGS = new Set([
      'BUTTON', 'A', 'INPUT', 'TEXTAREA', 'SELECT',
      'SUMMARY', 'DETAILS', 'OPTION', 'LABEL'
    ]);
    const INTERACTIVE_ROLES = new Set([
      'button', 'link', 'textbox', 'checkbox', 'radio',
      'combobox', 'menuitem', 'tab', 'switch', 'slider',
      'searchbox', 'menu', 'menubar', 'toolbar', 'dialog',
      'treeitem', 'option', 'gridcell'
    ]);

    const viewport = {
      width: window.innerWidth,
      height: window.innerHeight,
      scrollX: window.scrollX,
      scrollY: window.scrollY,
    };

    function isVisible(el) {
      const style = getComputedStyle(el);
      if (style.display === 'none') return false;
      if (style.visibility === 'hidden') return false;
      if (parseFloat(style.opacity) <= 0) return false;
      const rect = el.getBoundingClientRect();
      if (rect.width <= 0 || rect.height <= 0) return false;
      return true;
    }

    function isInViewport(el) {
      const rect = el.getBoundingClientRect();
      return (
        rect.top < viewport.height &&
        rect.bottom > 0 &&
        rect.left < viewport.width &&
        rect.right > 0
      );
    }

    function isInteractive(el) {
      if (el.tagName === 'INPUT' && el.type === 'hidden') return false;
      if (INTERACTIVE_TAGS.has(el.tagName)) return true;
      if (el.tagName === 'A' && el.hasAttribute('href')) return true;
      const role = el.getAttribute('role');
      if (role && INTERACTIVE_ROLES.has(role)) return true;
      if (el.hasAttribute('tabindex') && el.getAttribute('tabindex') !== '-1') return true;
      return false;
    }

    function generateSelector(el) {
      if (el.id) return '#' + CSS.escape(el.id);
      if (el.className && typeof el.className === 'string') {
        const classes = el.className.trim().split(/\\s+/).filter(c => c && !c.startsWith('__'));
        for (const cls of classes) {
          const matches = document.querySelectorAll('.' + CSS.escape(cls));
          if (matches.length === 1) return '.' + CSS.escape(cls);
        }
      }
      const parent = el.parentElement;
      if (parent) {
        const siblings = Array.from(parent.children);
        const index = siblings.indexOf(el) + 1;
        return el.tagName.toLowerCase() + ':nth-child(' + index + ')';
      }
      return el.tagName.toLowerCase();
    }

    function getAccessibleName(el) {
      const labelledBy = el.getAttribute('aria-labelledby');
      if (labelledBy) {
        const labelEl = document.getElementById(labelledBy);
        if (labelEl && labelEl.textContent) return labelEl.textContent.trim().slice(0, 100);
      }
      return (
        el.getAttribute('aria-label') ||
        el.getAttribute('title') ||
        el.getAttribute('placeholder') ||
        el.getAttribute('alt') ||
        (el.textContent || '').trim().slice(0, 100) ||
        ''
      );
    }

    const nodes = [];
    const allElements = document.querySelectorAll('*');

    for (const el of allElements) {
      if (!isInteractive(el)) continue;
      if (!isVisible(el)) continue;
      if (${viewportOnly} && !isInViewport(el)) continue;

      nodes.push({
        name: getAccessibleName(el),
        text: (el.textContent || '').trim().slice(0, 200),
        selector: generateSelector(el),
      });
    }

    return { nodes, viewport };
  })()`)

  return result
}

/**
 * 根据 CSS 选择器获取单个交互节点的详细信息
 * 返回 tag、role、name、text、selector、rect、visible、clickable、attributes、styles 等
 */
export async function extractInteractiveNodeDetail(
  wc: Electron.WebContents,
  selector: string,
): Promise<InteractiveNodeDetail | { error: string }> {
  const result = await wc.executeJavaScript(`(function() {
    const selector = ${JSON.stringify(selector)};
    const el = document.querySelector(selector);
    if (!el) return { error: 'Element not found for selector: ' + selector };

    function getAccessibleName(el) {
      const labelledBy = el.getAttribute('aria-labelledby');
      if (labelledBy) {
        const labelEl = document.getElementById(labelledBy);
        if (labelEl && labelEl.textContent) return labelEl.textContent.trim().slice(0, 100);
      }
      return (
        el.getAttribute('aria-label') ||
        el.getAttribute('title') ||
        el.getAttribute('placeholder') ||
        el.getAttribute('alt') ||
        (el.textContent || '').trim().slice(0, 100) ||
        ''
      );
    }

    const rect = el.getBoundingClientRect();
    const style = getComputedStyle(el);
    const role = el.getAttribute('role') || el.tagName.toLowerCase();

    // 收集有意义的属性（排除 class/style/事件等噪音）
    const skipAttrs = new Set(['class', 'style', 'id', 'tabindex']);
    const attributes = {};
    for (const attr of el.attributes) {
      if (!skipAttrs.has(attr.name) && !attr.name.startsWith('on')) {
        attributes[attr.name] = attr.value;
      }
    }

    const detail = {
      tag: el.tagName.toLowerCase(),
      role,
      name: getAccessibleName(el),
      text: (el.textContent || '').trim().slice(0, 500),
      selector: selector,
      rect: {
        x: Math.round(rect.x),
        y: Math.round(rect.y),
        width: Math.round(rect.width),
        height: Math.round(rect.height),
      },
      visible: style.display !== 'none' && style.visibility !== 'hidden' && parseFloat(style.opacity) > 0,
      clickable: el.tagName === 'BUTTON' || el.tagName === 'A' ||
                 role === 'button' || role === 'link' ||
                 el.hasAttribute('onclick') ||
                 style.cursor === 'pointer',
      attributes,
      styles: {
        display: style.display,
        visibility: style.visibility,
        opacity: style.opacity,
        cursor: style.cursor,
      },
    };

    // 输入类元素附加 value
    if ('value' in el) {
      detail.value = el.value;
    }
    // 链接附加 href
    if (el.tagName === 'A' && el.hasAttribute('href')) {
      detail.href = el.href;
    }

    return detail;
  })()`)

  return result
}

import { BrowserWindow } from 'electron'
import { pluginEventBus } from './plugin-event-bus'
import { PluginStorage } from './plugin-storage'
import type { PluginContext, PluginInfo } from './plugin-types'

export function createPluginContext(
  pluginInfo: PluginInfo,
  storage: PluginStorage,
  eventBus: typeof pluginEventBus,
  getMainWindow: () => BrowserWindow | null
): { context: PluginContext; cleanupEvents: () => void } {
  const prefix = `plugin:${pluginInfo.id}:`

  // 追踪所有通过 context.events 注册的监听器，卸载时逐一移除
  const registeredHandlers: Array<{ event: string; handler: (...args: any[]) => void }> = []

  const context: PluginContext = {
    events: {
      on(event: string, handler: (...args: any[]) => void): void {
        registeredHandlers.push({ event, handler })
        eventBus.on(event, handler)
      },
      once(event: string, handler: (...args: any[]) => void): void {
        registeredHandlers.push({ event, handler })
        eventBus.once(event, handler)
      },
      off(event: string, handler: (...args: any[]) => void): void {
        const idx = registeredHandlers.findIndex((h) => h.event === event && h.handler === handler)
        if (idx !== -1) registeredHandlers.splice(idx, 1)
        eventBus.off(event, handler)
      },
      emit(event: string, ...args: any[]): void {
        // 插件间通信：其他插件通过 plugin:{pluginId}:{event} 监听
        eventBus.emit(prefix + event, ...args)
      }
    },

    storage: {
      get: (key: string) => storage.get(key),
      set: (key: string, value: any) => storage.set(key, value),
      delete: (key: string) => storage.delete(key),
      clear: () => storage.clear(),
      keys: () => storage.keys()
    },

    plugin: pluginInfo,

    logger: {
      info(msg: string, ...args: any[]): void {
        console.log(`[Plugin:${pluginInfo.name}] ${msg}`, ...args)
      },
      warn(msg: string, ...args: any[]): void {
        console.warn(`[Plugin:${pluginInfo.name}] ${msg}`, ...args)
      },
      error(msg: string, ...args: any[]): void {
        console.error(`[Plugin:${pluginInfo.name}] ${msg}`, ...args)
      }
    },

    sendToRenderer(channel: string, ...args: any[]): void {
      const win = getMainWindow()
      if (!win || win.isDestroyed()) return
      win.webContents.send(channel, ...args)
    }
  }

  const cleanupEvents = () => {
    for (const { event, handler } of registeredHandlers) {
      eventBus.off(event, handler)
    }
    registeredHandlers.length = 0
  }

  return { context, cleanupEvents }
}

import { join, basename } from 'path'
import { existsSync, readdirSync, readFileSync, writeFileSync, mkdirSync, renameSync, rmSync } from 'node:fs'
import { app, BrowserWindow, shell, dialog } from 'electron'
import AdmZip from 'adm-zip'
import { pluginEventBus } from './plugin-event-bus'
import { PluginStorage } from './plugin-storage'
import { createPluginContext } from './plugin-context'
import type { PluginInfo, PluginMeta, PluginInstance } from './plugin-types'

class PluginManager {
  private plugins: Map<string, PluginInstance> = new Map()
  private disabledIds: Set<string> = new Set()
  private userDataPath: string
  private pluginsDir: string
  private mainWindow: BrowserWindow | null = null

  constructor() {
    this.userDataPath = app.getPath('userData')
    // 开发环境从项目 resources/plugins/ 加载，生产环境从 {userData}/plugins/ 加载
    this.pluginsDir = app.isPackaged
      ? join(this.userDataPath, 'plugins')
      : join(__dirname, '../../resources/plugins')
    this.loadDisabledList()
  }

  private loadDisabledList(): void {
    const filePath = join(this.userDataPath, 'plugin-data', 'disabled.json')
    try {
      if (existsSync(filePath)) {
        const ids: string[] = JSON.parse(readFileSync(filePath, 'utf-8'))
        this.disabledIds = new Set(ids)
      }
    } catch {
      this.disabledIds = new Set()
    }
  }

  private saveDisabledList(): void {
    const dir = join(this.userDataPath, 'plugin-data')
    if (!existsSync(dir)) mkdirSync(dir, { recursive: true })
    const filePath = join(dir, 'disabled.json')
    writeFileSync(filePath, JSON.stringify([...this.disabledIds], null, 2), 'utf-8')
  }

  /** 扫描并加载所有插件 */
  loadAll(): void {
    if (!existsSync(this.pluginsDir)) return
    const entries = readdirSync(this.pluginsDir, { withFileTypes: true })
    for (const entry of entries) {
      if (!entry.isDirectory()) continue
      const pluginDir = join(this.pluginsDir, entry.name)
      try {
        this.load(pluginDir)
      } catch (err) {
        console.error(`[PluginManager] 加载插件失败: ${pluginDir}`, err)
      }
    }
  }

  /** 设置主窗口引用（供插件 sendToRenderer 使用） */
  setMainWindow(win: BrowserWindow): void {
    this.mainWindow = win
  }

  /** 加载单个插件目录 */
  load(pluginDir: string): void {
    const infoPath = join(pluginDir, 'info.json')
    const mainPath = join(pluginDir, 'main.js')
    if (!existsSync(infoPath) || !existsSync(mainPath)) return

    const raw = readFileSync(infoPath, 'utf-8')
    const info: PluginInfo = JSON.parse(raw)

    if (!info.id || !info.name || !info.version || !info.description || !info.author?.name) {
      throw new Error(`插件 ${pluginDir} 的 info.json 缺少必需字段`)
    }

    if (this.plugins.has(info.id)) {
      console.warn(`[PluginManager] 插件 ${info.id} 已加载，跳过`)
      return
    }

    // 检查版本兼容性
    if (info.minAppVersion) {
      const appVersion = app.getVersion()
      if (appVersion < info.minAppVersion) {
        console.warn(
          `[PluginManager] 插件 ${info.name} 要求最低版本 ${info.minAppVersion}，当前 ${appVersion}`
        )
        return
      }
    }

    const storage = new PluginStorage(info.id, this.userDataPath)
    const { context, cleanupEvents } = createPluginContext(info, storage, pluginEventBus, () => this.mainWindow)
    const isDisabled = this.disabledIds.has(info.id)
    const pluginModule = require(mainPath)

    const instance: PluginInstance = {
      id: info.id,
      dir: pluginDir,
      info,
      enabled: !isDisabled,
      module: pluginModule,
      context,
      storage,
      cleanupEvents
    }

    this.plugins.set(info.id, instance)

    if (!isDisabled && typeof pluginModule.activate === 'function') {
      try {
        pluginModule.activate(context)
        console.log(`[PluginManager] 插件已激活: ${info.name} v${info.version}`)
      } catch (err) {
        console.error(`[PluginManager] 插件激活失败: ${info.name}`, err)
      }
    }
  }

  /** 卸载插件（从内存移除） */
  unload(pluginId: string): void {
    const instance = this.plugins.get(pluginId)
    if (!instance) return
    if (instance.enabled && typeof instance.module.deactivate === 'function') {
      try {
        instance.module.deactivate(instance.context)
      } catch (err) {
        console.error(`[PluginManager] 插件停用失败: ${instance.info.name}`, err)
      }
    }
    // 清理该插件注册的所有事件监听器
    instance.cleanupEvents()
    this.plugins.delete(pluginId)
    console.log(`[PluginManager] 插件已卸载: ${instance.info.name}`)
  }

  /** 启用插件 */
  enable(pluginId: string): void {
    const instance = this.plugins.get(pluginId)
    if (!instance || instance.enabled) return
    if (typeof instance.module.activate === 'function') {
      try {
        instance.module.activate(instance.context)
      } catch (err) {
        console.error(`[PluginManager] 插件激活失败: ${instance.info.name}`, err)
        return
      }
    }
    instance.enabled = true
    this.disabledIds.delete(pluginId)
    this.saveDisabledList()
  }

  /** 禁用插件 */
  disable(pluginId: string): void {
    const instance = this.plugins.get(pluginId)
    if (!instance || !instance.enabled) return
    if (typeof instance.module.deactivate === 'function') {
      try {
        instance.module.deactivate(instance.context)
      } catch (err) {
        console.error(`[PluginManager] 插件停用失败: ${instance.info.name}`, err)
      }
    }
    // 清理该插件注册的所有事件监听器
    instance.cleanupEvents()
    instance.enabled = false
    this.disabledIds.add(pluginId)
    this.saveDisabledList()
  }

  /** 获取所有插件元信息 */
  list(): PluginMeta[] {
    return Array.from(this.plugins.values()).map((instance) => ({
      id: instance.info.id,
      name: instance.info.name,
      version: instance.info.version,
      description: instance.info.description,
      author: instance.info.author,
      tags: instance.info.tags || [],
      hasView: instance.info.hasView || false,
      enabled: instance.enabled,
      iconPath: this.getIconPath(instance)
    }))
  }

  private getIconPath(instance: PluginInstance): string {
    const iconPath = join(instance.dir, 'icon.png')
    return existsSync(iconPath) ? iconPath : ''
  }

  getViewContent(pluginId: string): string | null {
    const instance = this.plugins.get(pluginId)
    if (!instance || !instance.info.hasView) return null
    const viewPath = join(instance.dir, 'view.js')
    if (!existsSync(viewPath)) return null
    try {
      return readFileSync(viewPath, 'utf-8')
    } catch {
      return null
    }
  }

  getIconBase64(pluginId: string): string | null {
    const instance = this.plugins.get(pluginId)
    if (!instance) return null
    const iconPath = join(instance.dir, 'icon.png')
    if (!existsSync(iconPath)) return null
    try {
      const buffer = readFileSync(iconPath)
      return `data:image/png;base64,${buffer.toString('base64')}`
    } catch {
      return null
    }
  }

  /** 解压后根据 info.json 的 id 确定最终目录，必要时重命名 */
  private resolveFinalDir(extractedDir: string, infoPath: string): string | null {
    const raw = readFileSync(infoPath, 'utf-8')
    const info = JSON.parse(raw)
    if (!info.id) return null

    const finalDir = join(this.pluginsDir, info.id)
    if (extractedDir === finalDir) return finalDir

    // 卸载已存在的同名插件（按目录路径匹配）
    const existing = Array.from(this.plugins.values()).find((p) => p.dir === finalDir)
    if (existing) this.unload(existing.id)

    if (existsSync(finalDir)) rmSync(finalDir, { recursive: true, force: true })
    renameSync(extractedDir, finalDir)
    return finalDir
  }

  /** 从 ZIP 文件导入插件 */
  async importFromZip(): Promise<{ success: boolean; pluginName?: string; error?: string }> {
    const result = await dialog.showOpenDialog({
      title: '选择插件 ZIP 文件',
      filters: [{ name: 'ZIP', extensions: ['zip'] }],
      properties: ['openFile']
    })

    if (result.canceled || result.filePaths.length === 0) {
      return { success: false, error: '已取消' }
    }

    const zipPath = result.filePaths[0]
    const zipFileName = basename(zipPath, '.zip')

    try {
      const zip = new AdmZip(zipPath)
      const entries = zip.getEntries()

      // 查找 info.json 所在的目录（插件根目录）
      const infoEntry = entries.find((e) => !e.isDirectory && e.entryName.endsWith('info.json'))
      if (!infoEntry) {
        return { success: false, error: 'ZIP 中未找到 info.json，不是有效的插件包' }
      }

      // 插件目录名：info.json 所在的顶级目录，或 ZIP 文件名
      const relativePath = infoEntry.entryName
      const topDir = relativePath.split('/')[0]
      const pluginDirName = relativePath.includes('/') ? topDir : zipFileName

      // 确保插件目录存在
      if (!existsSync(this.pluginsDir)) {
        mkdirSync(this.pluginsDir, { recursive: true })
      }

      const targetDir = join(this.pluginsDir, pluginDirName)

      // 如果插件已存在，先卸载
      const existingPlugin = Array.from(this.plugins.values()).find((p) => p.dir === targetDir)
      if (existingPlugin) {
        this.unload(existingPlugin.id)
      }

      // 解压到初始目录
      zip.extractAllTo(targetDir, true)

      // 校验解压结果
      const infoPath = join(targetDir, 'info.json')
      const mainPath = join(targetDir, 'main.js')
      if (!existsSync(infoPath) || !existsSync(mainPath)) {
        rmSync(targetDir, { recursive: true, force: true })
        return { success: false, error: '插件缺少 info.json 或 main.js，导入失败' }
      }

      // 使用 info.json 中的 id 作为最终目录名
      const finalDir = this.resolveFinalDir(targetDir, infoPath)
      if (!finalDir) {
        rmSync(targetDir, { recursive: true, force: true })
        return { success: false, error: '插件的 info.json 缺少 id 字段' }
      }

      this.load(finalDir)

      const instance = Array.from(this.plugins.values()).find((p) => p.dir === finalDir)
      if (!instance) {
        return { success: false, error: '插件加载失败' }
      }

      return { success: true, pluginName: instance.info.name }
    } catch (err: any) {
      return { success: false, error: `导入失败: ${err.message}` }
    }
  }

  /** 在系统文件管理器中打开插件目录 */
  openPluginsFolder(): void {
    const dir = this.pluginsDir
    if (!existsSync(dir)) {
      mkdirSync(dir, { recursive: true })
    }
    shell.openPath(dir)
  }

  /** 从 URL 下载并安装插件 ZIP */
  async installFromUrl(url: string): Promise<{ success: boolean; pluginName?: string; error?: string }> {
    try {
      const { net } = await import('electron')
      const response = await net.fetch(url)
      if (!response.ok) {
        return { success: false, error: `下载失败: HTTP ${response.status}` }
      }
      const arrayBuffer = await response.arrayBuffer()
      const buffer = Buffer.from(arrayBuffer)

      // 确保插件目录存在
      if (!existsSync(this.pluginsDir)) {
        mkdirSync(this.pluginsDir, { recursive: true })
      }

      // 写入临时 ZIP 文件
      const tmpZipPath = join(this.pluginsDir, `_tmp_${Date.now()}.zip`)
      writeFileSync(tmpZipPath, buffer)

      try {
        const zip = new AdmZip(tmpZipPath)
        const entries = zip.getEntries()
        const infoEntry = entries.find((e) => !e.isDirectory && e.entryName.endsWith('info.json'))
        if (!infoEntry) {
          return { success: false, error: 'ZIP 中未找到 info.json，不是有效的插件包' }
        }

        const relativePath = infoEntry.entryName
        const topDir = relativePath.split('/')[0]
        const pluginDirName = relativePath.includes('/') ? topDir : `plugin-${Date.now()}`

        const targetDir = join(this.pluginsDir, pluginDirName)

        // 如果插件已存在，先卸载
        const existingPlugin = Array.from(this.plugins.values()).find((p) => p.dir === targetDir)
        if (existingPlugin) {
          this.unload(existingPlugin.id)
        }

        zip.extractAllTo(targetDir, true)

        const infoPath = join(targetDir, 'info.json')
        const mainPath = join(targetDir, 'main.js')
        if (!existsSync(infoPath) || !existsSync(mainPath)) {
          rmSync(targetDir, { recursive: true, force: true })
          return { success: false, error: '插件缺少 info.json 或 main.js，安装失败' }
        }

        // 使用 info.json 中的 id 作为最终目录名
        const finalDir = this.resolveFinalDir(targetDir, infoPath)
        if (!finalDir) {
          rmSync(targetDir, { recursive: true, force: true })
          return { success: false, error: '插件的 info.json 缺少 id 字段' }
        }

        this.load(finalDir)
        const instance = Array.from(this.plugins.values()).find((p) => p.dir === finalDir)
        if (!instance) {
          return { success: false, error: '插件加载失败' }
        }

        return { success: true, pluginName: instance.info.name }
      } finally {
        // 清理临时 ZIP
        if (existsSync(tmpZipPath)) {
          rmSync(tmpZipPath, { force: true })
        }
      }
    } catch (err: any) {
      return { success: false, error: `安装失败: ${err.message}` }
    }
  }

  /** 卸载插件（从磁盘删除目录） */
  async uninstallPlugin(pluginId: string): Promise<{ success: boolean; error?: string }> {
    const instance = this.plugins.get(pluginId)
    if (!instance) {
      return { success: false, error: '插件未找到' }
    }
    try {
      this.unload(pluginId)
      rmSync(instance.dir, { recursive: true, force: true })
      return { success: true }
    } catch (err: any) {
      return { success: false, error: `卸载失败: ${err.message}` }
    }
  }

  shutdown(): void {
    for (const [id] of this.plugins) {
      this.unload(id)
    }
  }
}

export const pluginManager = new PluginManager()

import { app, session } from 'electron'
import * as http from 'node:http'
import * as https from 'node:https'
import * as net from 'node:net'
import * as tls from 'node:tls'
import type { Proxy } from './store'

const TEST_TARGET_HOST = 'httpbin.org'
const TEST_TARGET_PORT = 443
const TEST_TARGET_PATH = '/ip'
const REQUEST_TIMEOUT_MS = 15000

const sessionProxyAuthMap = new WeakMap<Electron.Session, Proxy>()
const proxyEndpointAuthMap = new Map<string, Proxy>()
const sessionLabelMap = new WeakMap<Electron.Session, string>()

let proxyAuthHandlerInitialized = false

function getProxyMode(proxy: Proxy): NonNullable<Proxy['proxyMode']> {
  return proxy.proxyMode ?? 'global'
}

function getProxyType(proxy: Proxy): NonNullable<Proxy['type']> {
  return proxy.type ?? 'socks5'
}

function getProxyEndpointKey(host: string, port: number | string): string {
  return `${host}:${Number(port)}`
}

function describeProxy(proxy: Proxy): string {
  return JSON.stringify({
    name: proxy.name,
    proxyMode: getProxyMode(proxy),
    type: proxy.type ?? '',
    host: proxy.host ?? '',
    port: proxy.port ?? '',
    username: proxy.username ?? '',
    passwordLength: proxy.password?.length ?? 0,
    pacScriptLength: proxy.pacScript?.length ?? 0,
    pacUrl: proxy.pacUrl ?? ''
  })
}

function getSessionLabel(ses?: Electron.Session): string {
  if (!ses) return 'unknown'
  return sessionLabelMap.get(ses) ?? 'unknown'
}

function getProxyAuthorizationValue(proxy: Proxy): string | null {
  if (!proxy.username) return null
  const token = Buffer.from(`${proxy.username}:${proxy.password || ''}`, 'utf8').toString('base64')
  return `Basic ${token}`
}

function assertGlobalProxyServer(proxy: Proxy): { host: string; port: number } {
  const host = proxy.host?.trim()
  const port = Number(proxy.port)
  if (!host || !Number.isFinite(port) || port <= 0) {
    throw new Error('全局代理模式需要有效的主机地址和端口')
  }
  return { host, port }
}

function buildPacDataUrl(content: string): string {
  return `data:application/x-ns-proxy-autoconfig;base64,${Buffer.from(content, 'utf8').toString('base64')}`
}

function buildPacProxyTarget(proxy: Proxy): string {
  const { host, port } = assertGlobalProxyServer(proxy)
  return `${getProxyType(proxy) === 'socks5' ? 'SOCKS5' : 'PROXY'} ${host}:${port}`
}

function buildGlobalPacScript(proxy: Proxy): string {
  return [
    'function FindProxyForURL(url, host) {',
    `  return '${buildPacProxyTarget(proxy)}';`,
    '}'
  ].join('\n')
}

function normalizeCustomPacScript(content?: string): string {
  const trimmed = content?.trim() ?? ''
  if (!trimmed) {
    throw new Error('自定义模式需要填写 PAC 脚本内容')
  }

  if (trimmed.includes('function FindProxyForURL')) {
    return trimmed
  }

  return [
    'function FindProxyForURL(url, host) {',
    trimmed,
    '}'
  ].join('\n')
}

export function buildProxyConfig(proxy: Proxy): Electron.ProxyConfig {
  const proxyMode = getProxyMode(proxy)

  if (proxyMode === 'custom') {
    return {
      mode: 'pac_script',
      pacScript: buildPacDataUrl(normalizeCustomPacScript(proxy.pacScript))
    }
  }

  if (proxyMode === 'pac_url') {
    const pacUrl = proxy.pacUrl?.trim()
    if (!pacUrl) {
      throw new Error('PAC 地址模式需要填写 PAC URL')
    }

    return {
      mode: 'pac_script',
      pacScript: pacUrl
    }
  }

  return {
    mode: 'pac_script',
    pacScript: buildPacDataUrl(buildGlobalPacScript(proxy))
  }
}

export async function applyProxyToSession(ses: Electron.Session, proxy: Proxy | null): Promise<void> {
  await ses.closeAllConnections()

  if (!proxy) {
    unregisterProxyAuth(ses)
    sessionLabelMap.set(ses, 'direct')
    await ses.setProxy({ mode: 'direct' })
    return
  }

  const proxyMode = getProxyMode(proxy)
  sessionLabelMap.set(ses, `${proxyMode}:${proxy.name}`)

  if (proxyMode === 'global' && proxy.username) {
    const { host, port } = assertGlobalProxyServer(proxy)
    registerProxyAuth(ses, { ...proxy, host, port })
  } else {
    unregisterProxyAuth(ses)
  }

  await ses.setProxy(buildProxyConfig(proxy))
}

export async function fetchSessionExitIp(ses: Electron.Session): Promise<string> {
  return await withTimeout(async () => {
    const response = await ses.fetch(`https://${TEST_TARGET_HOST}${TEST_TARGET_PATH}`, {
      method: 'GET',
      headers: {
        Accept: 'application/json',
        'User-Agent': 'session-box-proxy-test'
      }
    })

    if (!response.ok) {
      throw new Error(`HTTP ${response.status}`)
    }

    const data = await response.json() as { origin?: string }
    if (!data.origin || typeof data.origin !== 'string') {
      throw new Error('Invalid IP response')
    }

    return data.origin
  }, 'Session exit ip fetch')
}

async function testProxyThroughElectronSession(proxy: Proxy): Promise<{ ok: boolean; ip?: string; error?: string }> {
  return await withTimeout(async () => {
    const partition = `proxy-test:${Date.now()}:${Math.random().toString(36).slice(2)}`
    const ses = session.fromPartition(partition)

    try {
      await applyProxyToSession(ses, proxy)

      return {
        ok: true,
        ip: await fetchSessionExitIp(ses)
      }
    } catch (error) {
      return {
        ok: false,
        error: error instanceof Error ? error.message : String(error)
      }
    } finally {
      await applyProxyToSession(ses, null).catch(() => undefined)
    }
  }, 'Electron session proxy test')
}

function ensureProxyAuthHandler(): void {
  if (proxyAuthHandlerInitialized) return

  console.log('[ProxyAuth] initialize global login handler')

  app.on('login', (event, webContents, _request, authInfo, callback) => {
    if (!authInfo.isProxy) return

    const sessionProxy = webContents ? sessionProxyAuthMap.get(webContents.session) : undefined
    const endpointProxy = proxyEndpointAuthMap.get(getProxyEndpointKey(authInfo.host, authInfo.port))
    const proxy = sessionProxy ?? endpointProxy

    console.log('[ProxyAuth] login event', {
      hasWebContents: !!webContents,
      partition: getSessionLabel(webContents?.session),
      authHost: authInfo.host,
      authPort: authInfo.port,
      realm: authInfo.realm,
      scheme: authInfo.scheme,
      matchedBySession: !!sessionProxy,
      matchedByEndpoint: !!endpointProxy,
      hasProxyCredentials: !!proxy?.username
    })

    if (!proxy?.username) return

    event.preventDefault()
    console.log('[ProxyAuth] credentials applied', {
      partition: getSessionLabel(webContents?.session),
      proxy: describeProxy(proxy)
    })
    callback(proxy.username, proxy.password || '')
  })

  proxyAuthHandlerInitialized = true
}

export function registerProxyAuth(ses: Electron.Session, proxy: Proxy): void {
  ensureProxyAuthHandler()
  const { host, port } = assertGlobalProxyServer(proxy)
  sessionLabelMap.set(ses, `${getProxyType(proxy)}://${host}:${port}`)

  if (!proxy.username) {
    console.log('[ProxyAuth] unregister because proxy has no username', {
      partition: getSessionLabel(ses),
      proxy: describeProxy(proxy)
    })
    unregisterProxyAuth(ses)
    return
  }

  sessionProxyAuthMap.set(ses, proxy)
  proxyEndpointAuthMap.set(getProxyEndpointKey(host, port), { ...proxy, host, port })

  console.log('[ProxyAuth] register', {
    partition: getSessionLabel(ses),
    proxy: describeProxy(proxy)
  })
}

export function unregisterProxyAuth(ses: Electron.Session): void {
  const existingProxy = sessionProxyAuthMap.get(ses)

  if (existingProxy) {
    const { host, port } = assertGlobalProxyServer(existingProxy)
    proxyEndpointAuthMap.delete(getProxyEndpointKey(host, port))
    console.log('[ProxyAuth] unregister', {
      partition: getSessionLabel(ses),
      proxy: describeProxy(existingProxy)
    })
  }

  sessionProxyAuthMap.delete(ses)
}

function withTimeout<T>(promiseFactory: () => Promise<T>, label: string): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    const timer = setTimeout(() => {
      reject(new Error(`${label} timeout after ${REQUEST_TIMEOUT_MS}ms`))
    }, REQUEST_TIMEOUT_MS)

    void promiseFactory()
      .then((value) => {
        clearTimeout(timer)
        resolve(value)
      })
      .catch((error) => {
        clearTimeout(timer)
        reject(error)
      })
  })
}

function requestThroughTlsSocket(socket: tls.TLSSocket, proxy: Proxy): Promise<{ ok: boolean; ip?: string; error?: string }> {
  return new Promise((resolve) => {
    let settled = false
    let raw = ''

    const finish = (result: { ok: boolean; ip?: string; error?: string }): void => {
      if (settled) return
      settled = true
      socket.destroy()
      resolve(result)
    }

    socket.setEncoding('utf8')
    socket.setTimeout(REQUEST_TIMEOUT_MS, () => {
      finish({ ok: false, error: 'Target request timeout' })
    })

    socket.on('data', (chunk: string) => {
      raw += chunk
    })

    socket.on('error', (error) => {
      console.error('[ProxyTestNative] target socket error', {
        proxyType: proxy.type,
        message: error.message
      })
      finish({ ok: false, error: error.message })
    })

    socket.on('end', () => {
      const separator = '\r\n\r\n'
      const headerEnd = raw.indexOf(separator)
      if (headerEnd === -1) {
        finish({ ok: false, error: 'Invalid target response' })
        return
      }

      const headerText = raw.slice(0, headerEnd)
      const body = raw.slice(headerEnd + separator.length)
      const statusLine = headerText.split('\r\n')[0] || ''
      const match = statusLine.match(/^HTTP\/\d\.\d\s+(\d{3})/)
      const statusCode = match ? Number(match[1]) : 0

      console.log('[ProxyTestNative] target response', {
        proxyType: proxy.type,
        statusCode,
        body
      })

      if (statusCode !== 200) {
        finish({ ok: false, error: `Target HTTP ${statusCode || 'unknown'}` })
        return
      }

      try {
        const data = JSON.parse(body) as { origin: string }
        finish({ ok: true, ip: data.origin })
      } catch {
        finish({ ok: false, error: '解析响应失败' })
      }
    })

    const requestText = [
      `GET ${TEST_TARGET_PATH} HTTP/1.1`,
      `Host: ${TEST_TARGET_HOST}`,
      'Accept: application/json',
      'Connection: close',
      'User-Agent: session-box-proxy-test',
      '',
      ''
    ].join('\r\n')

    socket.write(requestText)
  })
}

function createTlsTunnel(socket: net.Socket, proxy: Proxy, head?: Buffer): Promise<tls.TLSSocket> {
  return new Promise((resolve, reject) => {
    if (head && head.length > 0) {
      socket.unshift(head)
    }

    const tlsSocket = tls.connect({
      socket,
      servername: TEST_TARGET_HOST
    })

    tlsSocket.setTimeout(REQUEST_TIMEOUT_MS, () => {
      tlsSocket.destroy(new Error('TLS tunnel timeout'))
    })

    tlsSocket.once('secureConnect', () => {
      console.log('[ProxyTestNative] tls tunnel established', {
        proxyType: proxy.type,
        proxyHost: proxy.host,
        proxyPort: proxy.port
      })
      resolve(tlsSocket)
    })

    tlsSocket.once('error', reject)
  })
}

function testHttpConnectProxy(proxy: Proxy): Promise<{ ok: boolean; ip?: string; error?: string }> {
  return withTimeout(async () => {
    const { host, port } = assertGlobalProxyServer(proxy)
    console.log('[ProxyTestNative] begin http connect', {
      proxy: describeProxy(proxy)
    })

    const headers: Record<string, string> = {
      Host: `${TEST_TARGET_HOST}:${TEST_TARGET_PORT}`,
      Connection: 'keep-alive',
      'Proxy-Connection': 'keep-alive',
      'User-Agent': 'session-box-proxy-test'
    }

    const authorization = getProxyAuthorizationValue(proxy)
    if (authorization) {
      headers['Proxy-Authorization'] = authorization
    }

    const requestModule = proxy.type === 'https' ? https : http

    return await new Promise<{ ok: boolean; ip?: string; error?: string }>((resolve) => {
      let settled = false

      const finish = (result: { ok: boolean; ip?: string; error?: string }): void => {
        if (settled) return
        settled = true
        resolve(result)
      }

      const connectRequest = requestModule.request({
        host,
        port,
        method: 'CONNECT',
        path: `${TEST_TARGET_HOST}:${TEST_TARGET_PORT}`,
        headers
      })

      connectRequest.setTimeout(REQUEST_TIMEOUT_MS, () => {
        connectRequest.destroy(new Error('CONNECT timeout'))
      })

      connectRequest.on('connect', async (response, socket, head) => {
        console.log('[ProxyTestNative] connect response', {
          proxyType: proxy.type,
          statusCode: response.statusCode,
          statusMessage: response.statusMessage,
          headers: response.headers
        })

        if (response.statusCode !== 200) {
          socket.destroy()
          finish({ ok: false, error: `Proxy HTTP ${response.statusCode}` })
          return
        }

        try {
          const tlsSocket = await createTlsTunnel(socket, proxy, head)
          const result = await requestThroughTlsSocket(tlsSocket, proxy)
          finish(result)
        } catch (error) {
          finish({
            ok: false,
            error: error instanceof Error ? error.message : String(error)
          })
        }
      })

      connectRequest.on('response', (response) => {
        console.log('[ProxyTestNative] unexpected non-connect response', {
          proxyType: proxy.type,
          statusCode: response.statusCode,
          headers: response.headers
        })
      })

      connectRequest.on('error', (error) => {
        console.error('[ProxyTestNative] connect error', {
          proxyType: proxy.type,
          message: error.message
        })
        finish({ ok: false, error: error.message })
      })

      connectRequest.end()
    })
  }, 'HTTP CONNECT proxy test')
}

function readExact(socket: net.Socket, size: number): Promise<Buffer> {
  return new Promise((resolve, reject) => {
    let chunks: Buffer[] = []
    let total = 0

    const cleanup = (): void => {
      socket.off('data', onData)
      socket.off('error', onError)
      socket.off('close', onClose)
    }

    const onError = (error: Error): void => {
      cleanup()
      reject(error)
    }

    const onClose = (): void => {
      cleanup()
      reject(new Error('SOCKS5 socket closed'))
    }

    const onData = (chunk: Buffer): void => {
      chunks.push(chunk)
      total += chunk.length

      if (total < size) return

      cleanup()
      const buffer = Buffer.concat(chunks, total)
      const required = buffer.subarray(0, size)
      const rest = buffer.subarray(size)
      if (rest.length > 0) {
        socket.unshift(rest)
      }
      resolve(required)
    }

    socket.on('data', onData)
    socket.once('error', onError)
    socket.once('close', onClose)
  })
}

async function readSocks5Reply(socket: net.Socket): Promise<void> {
  const header = await readExact(socket, 4)
  const atyp = header[3]

  let restLength = 0
  if (atyp === 0x01) restLength = 4 + 2
  else if (atyp === 0x03) {
    const domainLength = (await readExact(socket, 1))[0]
    restLength = domainLength + 2
  } else if (atyp === 0x04) restLength = 16 + 2
  else throw new Error(`Unsupported SOCKS5 ATYP: ${atyp}`)

  const rest = await readExact(socket, restLength)
  const response = Buffer.concat([header, restLength === rest.length ? rest : Buffer.alloc(0)])

  if (response[1] !== 0x00) {
    throw new Error(`SOCKS5 connect failed: ${response[1]}`)
  }
}

function testSocks5Proxy(proxy: Proxy): Promise<{ ok: boolean; ip?: string; error?: string }> {
  return withTimeout(async () => {
    const { host, port } = assertGlobalProxyServer(proxy)
    console.log('[ProxyTestNative] begin socks5 connect', {
      proxy: describeProxy(proxy)
    })

    const socket = net.connect({
      host,
      port
    })

    socket.setTimeout(REQUEST_TIMEOUT_MS, () => {
      socket.destroy(new Error('SOCKS5 timeout'))
    })

    await new Promise<void>((resolve, reject) => {
      socket.once('connect', resolve)
      socket.once('error', reject)
    })

    const methods = proxy.username ? [0x00, 0x02] : [0x00]
    socket.write(Buffer.from([0x05, methods.length, ...methods]))

    const authSelection = await readExact(socket, 2)
    if (authSelection[0] !== 0x05) {
      throw new Error('Invalid SOCKS5 handshake version')
    }

    if (authSelection[1] === 0xff) {
      throw new Error('SOCKS5 no acceptable auth method')
    }

    if (authSelection[1] === 0x02) {
      const username = Buffer.from(proxy.username || '', 'utf8')
      const password = Buffer.from(proxy.password || '', 'utf8')
      const authPacket = Buffer.concat([
        Buffer.from([0x01, username.length]),
        username,
        Buffer.from([password.length]),
        password
      ])
      socket.write(authPacket)

      const authResponse = await readExact(socket, 2)
      if (authResponse[1] !== 0x00) {
        throw new Error(`SOCKS5 auth failed: ${authResponse[1]}`)
      }
    }

    const hostBuffer = Buffer.from(TEST_TARGET_HOST, 'utf8')
    const portBuffer = Buffer.alloc(2)
    portBuffer.writeUInt16BE(TEST_TARGET_PORT, 0)

    const connectPacket = Buffer.concat([
      Buffer.from([0x05, 0x01, 0x00, 0x03, hostBuffer.length]),
      hostBuffer,
      portBuffer
    ])

    socket.write(connectPacket)
    await readSocks5Reply(socket)

    console.log('[ProxyTestNative] socks5 tunnel established', {
      proxyHost: proxy.host,
      proxyPort: proxy.port
    })

    const tlsSocket = await createTlsTunnel(socket, proxy)
    return await requestThroughTlsSocket(tlsSocket, proxy)
  }, 'SOCKS5 proxy test')
}

export async function testProxy(proxy: Proxy): Promise<{ ok: boolean; ip?: string; error?: string }> {
  try {
    const proxyMode = getProxyMode(proxy)

    if (proxyMode === 'custom' || proxyMode === 'pac_url') {
      return await testProxyThroughElectronSession(proxy)
    }

    if (getProxyType(proxy) === 'socks5') {
      return await testSocks5Proxy(proxy)
    }

    if (getProxyType(proxy) === 'http' || getProxyType(proxy) === 'https') {
      return await testHttpConnectProxy(proxy)
    }

    return { ok: false, error: `Unsupported proxy type: ${getProxyType(proxy)}` }
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error)
    console.error('[ProxyTestNative] fatal error', {
      proxy: describeProxy(proxy),
      message
    })
    return { ok: false, error: message }
  }
}

