// src/composables/useCommandPalette.ts

import { ref, shallowRef } from 'vue'
import type { CommandItem, CommandProvider } from '@/types/command'

export interface ParsedQuery {
  /** 匹配到的 Provider（null 表示无匹配或空输入） */
  provider: CommandProvider | null
  /** 搜索关键词 */
  query: string
  /** 是否为未识别的前缀（如 "xyz foo" 中 xyz 不是任何 Provider 的前缀） */
  unknownPrefix: boolean
}

export function useCommandPalette() {
  const providers = shallowRef<CommandProvider[]>([])
  const results = ref<Map<string, CommandItem[]>>(new Map())
  const loading = ref(false)
  const activeProvider = ref<CommandProvider | null>(null)
  const queryText = ref('')

  /** 注册一个 Provider */
  function registerProvider(provider: CommandProvider) {
    providers.value = [...providers.value, provider]
  }

  /** 批量注册 Provider */
  function registerProviders(list: CommandProvider[]) {
    providers.value = [...providers.value, ...list]
  }

  /** 激活某个 Provider */
  function activateProvider(provider: CommandProvider) {
    activeProvider.value = provider
    queryText.value = ''
    searchWithProvider(provider, '')
  }

  /** 取消激活，回到默认状态 */
  function deactivateProvider() {
    activeProvider.value = null
    queryText.value = ''
    search('')
  }

  /** 解析输入的前缀，返回匹配的 Provider 和剩余 query */
  function parseQuery(input: string): ParsedQuery {
    const trimmed = input.trim()
    if (!trimmed) return { provider: null, query: '', unknownPrefix: false }

    const spaceIdx = trimmed.indexOf(' ')
    const firstToken = (spaceIdx === -1 ? trimmed : trimmed.slice(0, spaceIdx)).toLowerCase()
    const restQuery = spaceIdx === -1 ? '' : trimmed.slice(spaceIdx + 1).trim()

    // 还没有空格，用户还在打字前缀
    if (spaceIdx === -1) {
      return { provider: null, query: trimmed, unknownPrefix: false }
    }

    const matched = providers.value.find(
      (p) => p.prefix.toLowerCase() === firstToken || (p.prefixShort && p.prefixShort.toLowerCase() === firstToken)
    )

    if (matched) {
      return { provider: matched, query: restQuery, unknownPrefix: false }
    }

    // 有空格但前缀不匹配任何 Provider → 未识别前缀
    return { provider: null, query: trimmed, unknownPrefix: true }
  }

  /** 使用指定 Provider 执行搜索 */
  async function searchWithProvider(provider: CommandProvider, query: string) {
    const resultMap = new Map<string, CommandItem[]>()
    loading.value = true
    try {
      const items = await provider.search(query)
      resultMap.set(provider.id, items)
    } finally {
      loading.value = false
    }
    results.value = resultMap
  }

  /** 执行搜索（完整输入，含前缀解析） */
  async function search(input: string) {
    const { provider, query, unknownPrefix } = parseQuery(input)
    const resultMap = new Map<string, CommandItem[]>()
    loading.value = true

    try {
      // 前缀匹配成功时，自动激活对应 Provider
      if (provider) {
        activeProvider.value = provider
        queryText.value = query
        const items = await provider.search(query)
        resultMap.set(provider.id, items)
      } else if (unknownPrefix) {
        // 未识别前缀：不搜索任何 Provider，返回空结果
      } else if (!input.trim()) {
        // 空输入：查找全局命令 Provider
        activeProvider.value = null
        queryText.value = ''
        const globalProvider = providers.value.find((p) => p.prefix === '')
        if (globalProvider) {
          const items = await globalProvider.search('')
          resultMap.set(globalProvider.id, items)
        }
      } else {
        activeProvider.value = null
        queryText.value = input.trim()
        // 无前缀匹配：只展示全局命令 + 匹配的 Provider 工具列表
        const globalProvider = providers.value.find((p) => p.prefix === '')
        if (globalProvider) {
          const items = await globalProvider.search(input.trim())
          if (items.length > 0) {
            resultMap.set(globalProvider.id, items)
          }
        }

        // 过滤匹配输入的 Provider，展示为可选项
        const q = input.trim().toLowerCase()
        const matchedProviders = providers.value.filter(
          (p) =>
            p.prefix !== '' &&
            (p.prefix.toLowerCase().includes(q) ||
              (p.prefixShort && p.prefixShort.toLowerCase().includes(q)) ||
              p.label.toLowerCase().includes(q))
        )
        if (matchedProviders.length > 0) {
          const providerItems: CommandItem[] = matchedProviders.map((p) => ({
            id: `provider-${p.id}`,
            label: `${p.prefix}${p.prefixShort ? ` (${p.prefixShort})` : ''}`,
            description: `搜索${p.label}`,
            icon: p.icon,
            keywords: [p.prefix, p.prefixShort || '', p.label],
            run: () => {},
          }))
          resultMap.set('__providers__', providerItems)
        }
      }
    } finally {
      loading.value = false
    }

    results.value = resultMap
  }

  return {
    providers,
    results,
    loading,
    activeProvider,
    queryText,
    registerProvider,
    registerProviders,
    activateProvider,
    deactivateProvider,
    searchWithProvider,
    parseQuery,
    search,
  }
}

import { toast } from 'vue-sonner'

// ===== 类型定义 =====

/** 通知操作按钮 */
export interface NotificationAction {
  label: string
  onClick: () => void
}

/** 通知选项（对象形式调用时使用） */
export interface NotificationOptions {
  /** 通知标题 */
  title: string
  /** 通知描述（可选副标题） */
  description?: string
  /** 自动关闭时长(ms)，设为 Infinity 则不自动关闭 */
  duration?: number
  /** 操作按钮 */
  action?: NotificationAction
  /** 取消按钮 */
  cancel?: NotificationAction
  /** 自定义唯一 ID，可用于后续 dismiss */
  id?: string | number
}

/** Promise 通知的文案配置 */
export interface PromiseNotificationMessages {
  loading: string
  success: string | ((data: any) => string)
  error: string | ((error: any) => string)
}

// ===== 通知中心 =====

/** 默认自动关闭时长 */
const DEFAULT_DURATION = 4000

/**
 * 通知中心 Composable
 *
 * 基于 vue-sonner 封装，提供语义化的通知方法。
 * 所有 Vue 组件均可通过此 composable 发送通知，无需直接依赖 vue-sonner。
 *
 * @example
 * ```ts
 * const notify = useNotification()
 *
 * // 简单调用
 * notify.success('保存成功')
 * notify.error('网络异常')
 *
 * // 带描述
 * notify.warning({ title: '空间不足', description: '磁盘使用率已达 95%' })
 *
 * // 带操作按钮
 * notify.info({
 *   title: '发现新版本',
 *   action: { label: '立即更新', onClick: () => doUpdate() }
 * })
 *
 * // 异步任务
 * notify.promise(saveData(), {
 *   loading: '保存中...',
 *   success: '保存成功',
 *   error: '保存失败'
 * })
 *
 * // 手动关闭
 * const id = notify.loading('处理中...')
 * notify.dismiss(id)
 * ```
 */
export function useNotification() {
  /** 构建 vue-sonner 所需的 options 对象 */
  function buildSonnerOptions(options?: NotificationOptions) {
    if (!options) return undefined
    const opts: Record<string, any> = {
      description: options.description,
      duration: options.duration ?? DEFAULT_DURATION,
    }
    if (options.id != null) opts.id = options.id
    if (options.action) {
      opts.action = {
        label: options.action.label,
        onClick: options.action.onClick,
      }
    }
    if (options.cancel) {
      opts.cancel = {
        label: options.cancel.label,
        onClick: options.cancel.onClick,
      }
    }
    return opts
  }

  /** 解析参数：支持 string 或 NotificationOptions */
  function resolveArgs(
    messageOrOptions: string | NotificationOptions
  ): [string, Record<string, any> | undefined] {
    if (typeof messageOrOptions === 'string') {
      return [messageOrOptions, { duration: DEFAULT_DURATION }]
    }
    const { title, ...rest } = messageOrOptions
    return [title, buildSonnerOptions(rest)]
  }

  return {
    /** 成功通知（绿色） */
    success(messageOrOptions: string | NotificationOptions) {
      const [msg, opts] = resolveArgs(messageOrOptions)
      return toast.success(msg, opts)
    },

    /** 错误通知（红色） */
    error(messageOrOptions: string | NotificationOptions) {
      const [msg, opts] = resolveArgs(messageOrOptions)
      return toast.error(msg, opts)
    },

    /** 警告通知（黄色） */
    warning(messageOrOptions: string | NotificationOptions) {
      const [msg, opts] = resolveArgs(messageOrOptions)
      return toast.warning(msg, opts)
    },

    /** 信息通知（蓝色） */
    info(messageOrOptions: string | NotificationOptions) {
      const [msg, opts] = resolveArgs(messageOrOptions)
      return toast.info(msg, opts)
    },

    /** 加载中通知（不自动关闭，需手动 dismiss） */
    loading(messageOrOptions: string | NotificationOptions) {
      if (typeof messageOrOptions === 'string') {
        return toast.loading(messageOrOptions, { duration: Infinity })
      }
      const { title, ...rest } = messageOrOptions
      rest.duration ??= Infinity
      return toast.loading(title, buildSonnerOptions(rest))
    },

    /**
     * Promise 通知 —— 自动跟踪异步任务状态
     *
     * @param promise 异步任务
     * @param messages 各阶段文案
     * @returns 原始 promise 的结果
     */
    promise<T>(promise: Promise<T>, messages: PromiseNotificationMessages) {
      return toast.promise(promise, {
        loading: messages.loading,
        success: messages.success,
        error: messages.error,
      })
    },

    /** 关闭指定通知（传 ID），或关闭全部（不传参） */
    dismiss(id?: string | number) {
      return toast.dismiss(id)
    },
  }
}

import { createToolDiscoveryTools } from './tools'
import { listenToChatStream, type StreamCallbacks } from './stream'
