/** Agent 流式请求的可选配置 */
export interface AgentStreamOptions {
  /** 运行模式：浏览器模式（默认）或工作流模式 */
  mode?: 'browser' | 'workflow'
  /** 工作流 ID（仅 workflow 模式） */
  workflowId?: string
  /** 工作流摘要信息（仅 workflow 模式） */
  workflowSummary?: {
    id: string
    name: string
    description?: string
    nodes: Array<{ id: string; type: string; label: string }>
    edges: Array<{ id: string; source: string; target: string }>
  }
}

/**
 * 通过主进程 API 代理运行 Agent 流式请求。
 * 渲染进程构造请求参数，主进程注入 API Key 并转发到 LLM 供应商。
 * 返回 requestId（用于 abort）和 cleanup（用于清理 IPC 监听器）。
 */
export async function runAgentStream(
  history: Array<{ role: string; content: string }>,
  input: string,
  images: string[] | undefined,
  callbacks: StreamCallbacks,
  targetTabId: string | null,
  enabledToolNames?: Set<string>,
  options?: AgentStreamOptions,
): Promise<{ requestId: string; cleanup: () => void }> {
  const providerStore = useAIProviderStore()
  const provider = providerStore.currentProvider
  const model = providerStore.currentModel

  if (!provider || !model) {
    callbacks.onError(new Error('请先配置 AI 供应商和模型'))
    return { requestId: '', cleanup: () => {} }
  }

  const isWorkflow = options?.mode === 'workflow'

  // 构造消息（含图片支持）
  const userContent = images?.length
    ? [
        ...images.map((img) => ({
          type: 'image' as const,
          source: { type: 'base64' as const, media_type: 'image/png' as const, data: img },
        })),
        { type: 'text' as const, text: input },
      ]
    : input

  const messages = [
    ...history.map((h) => ({
      role: h.role,
      content: h.content,
    })),
    { role: 'user', content: userContent },
  ]

  // 工作流模式使用专用工具定义，浏览器模式使用工具发现系统
  const tools = isWorkflow
    ? WORKFLOW_TOOL_DEFINITIONS
    : createToolDiscoveryTools()

  // 系统提示词
  const systemPrompt = isWorkflow
    ? buildWorkflowSystemPrompt(options!.workflowSummary!)
    : BROWSER_AGENT_SYSTEM_PROMPT

  const requestId = crypto.randomUUID()

  // 监听流式回调
  const cleanup = listenToChatStream(requestId, callbacks)

  // 发送请求到主进程
  try {
    await window.api.chat.completions({
      _requestId: requestId,
      providerId: provider.id,
      modelId: model.id,
      system: systemPrompt,
      messages,
      tools: tools as unknown as Array<Record<string, unknown>>,
      stream: true,
      maxTokens: model.maxTokens || 4096,
      ...(isWorkflow
        ? {
            _mode: 'workflow' as const,
            _workflowId: options!.workflowId,
          }
        : {
            targetTabId: targetTabId ?? undefined,
            enabledToolNames: enabledToolNames ? Array.from(enabledToolNames) : undefined,
          }),
      ...(model.supportsThinking ? { thinking: { type: 'enabled' as const, budgetTokens: 2000 } } : {}),
    })
  } catch (error) {
    cleanup()
    callbacks.onError(error instanceof Error ? error : new Error(String(error)))
  }

  return { requestId, cleanup }
}

import type { ToolCall } from '@/types'

export interface ToolResultEvent {
  requestId: string
  toolUseId: string
  name: string
  result: unknown
}

export interface ToolCallArgsEvent {
  requestId: string
  toolUseId: string
  args: Record<string, unknown>
}

export interface RetryEvent {
  requestId: string
  attempt: number
  maxRetries: number
  delayMs: number
  status: number
  error: string
}

export interface StreamCallbacks {
  onToken: (token: string) => void
  onToolCall: (call: ToolCall) => void
  onToolResult: (event: ToolResultEvent) => void
  onToolCallArgs: (event: ToolCallArgsEvent) => void
  onThinking: (content: string, blockIndex: number) => void
  onUsage: (usage: { inputTokens: number; outputTokens: number }) => void
  onRetry?: (event: RetryEvent) => void
  onDone: () => void
  onError: (error: Error) => void
}

/**
 * 监听主进程回传的聊天流事件。
 * 返回清理函数用于移除监听。
 */
export function listenToChatStream(requestId: string, callbacks: StreamCallbacks): () => void {
  const unsubscribers: Array<() => void> = []

  unsubscribers.push(
    window.api.on('chat:chunk', (data: any) => {
      if (data.requestId === requestId) {
        callbacks.onToken(data.token)
      }
    }),
  )

  unsubscribers.push(
    window.api.on('chat:tool-call', (data: any) => {
      if (data.requestId === requestId) {
        callbacks.onToolCall(data.toolCall)
      }
    }),
  )

  unsubscribers.push(
    window.api.on('chat:tool-result', (data: any) => {
      if (data.requestId === requestId) {
        callbacks.onToolResult(data)
      }
    }),
  )

  unsubscribers.push(
    window.api.on('chat:tool-call-args', (data: any) => {
      if (data.requestId === requestId) {
        callbacks.onToolCallArgs(data)
      }
    }),
  )

  unsubscribers.push(
    window.api.on('chat:thinking', (data: any) => {
      if (data.requestId === requestId) {
        callbacks.onThinking(data.content, data.index)
      }
    }),
  )

  unsubscribers.push(
    window.api.on('chat:done', (data: any) => {
      if (data.requestId === requestId) {
        // 如果 done 事件携带 usage，先回调
        if (data.usage) {
          callbacks.onUsage(data.usage)
        }
        callbacks.onDone()
        unsubscribers.forEach((fn) => fn())
      }
    }),
  )

  unsubscribers.push(
    window.api.on('chat:error', (data: any) => {
      if (data.requestId === requestId) {
        callbacks.onError(new Error(data.error))
        unsubscribers.forEach((fn) => fn())
      }
    }),
  )

  unsubscribers.push(
    window.api.on('chat:retry', (data: any) => {
      if (data.requestId === requestId) {
        callbacks.onRetry?.(data)
      }
    }),
  )

  unsubscribers.push(
    window.api.on('chat:usage', (data: any) => {
      if (data.requestId === requestId) {
        callbacks.onUsage({ inputTokens: data.inputTokens, outputTokens: data.outputTokens })
      }
    }),
  )

  return () => unsubscribers.forEach((fn) => fn())
}

